def _run_level1_evidence_normalization_check() -> dict:
    """Run Level 1 evidence normalization / clean-cycle consistency check (Phase 16F).

    Compares KPI clean_cycles against the canonical clean-cycle ledger source
    used by the Level 1 stability drill. Proves the drill and KPI agree on
    clean_cycles count and source.
    """
    import hashlib
    import json as _json
    import subprocess as _sp
    import urllib.request
    import urllib.error
    from datetime import datetime, timezone
    from typing import Any

    now_utc = datetime.now(timezone.utc)
    ts_str = now_utc.strftime("%Y-%m-%dT%H:%M:%SZ")
    ts_file = now_utc.strftime("%Y%m%dT%H%M%SZ")
    check_id = f"evidence-normalization-{ts_file}"

    # ------------------------------------------------------------------
    # 1. Git / worktree
    # ------------------------------------------------------------------
    git = _git_metadata(BRIDGE_DIR)
    full_commit = git.get("commit_short", "?")
    try:
        p = _sp.run(
            ["git", "-C", str(BRIDGE_DIR), "rev-parse", "HEAD"],
            capture_output=True, text=True, timeout=5,
        )
        if p.stdout.strip():
            full_commit = p.stdout.strip()
    except Exception:
        pass

    worktree = _get_worktree_state(BRIDGE_DIR)
    origin_alignment = _get_origin_master_alignment(BRIDGE_DIR)

    git_section = {
        "branch": git.get("branch", "?"),
        "commit": full_commit if len(full_commit) > 16 else git.get("commit_short", "?"),
        "commit_short": git.get("commit_short", "?"),
        "tag": git.get("tag", "?"),
        "origin_master_commit": origin_alignment.get("origin_master_commit", "?"),
        "origin_master_aligned": origin_alignment.get("aligned"),
        "worktree_clean": worktree.get("clean"),
        "dirty_files": worktree.get("dirty_files", []),
    }

    # ------------------------------------------------------------------
    # 2. Required tags
    # ------------------------------------------------------------------
    import subprocess as _sp2
    required_tags_present: list[str] = []
    required_tags_missing: list[str] = []
    try:
        p = _sp2.run(
            ["git", "-C", str(BRIDGE_DIR), "tag"],
            capture_output=True, text=True, timeout=10,
        )
        all_tags = set(p.stdout.strip().splitlines())
        for tag in _PHASE16F_REQUIRED_TAGS:
            if tag in all_tags:
                required_tags_present.append(tag)
            else:
                required_tags_missing.append(tag)
    except Exception:
        required_tags_missing = list(_PHASE16F_REQUIRED_TAGS)
        required_tags_present = []

    required_tags = {
        "required_count": len(_PHASE16F_REQUIRED_TAGS),
        "present_count": len(required_tags_present),
        "missing": required_tags_missing,
        "present": required_tags_present,
    }

    # Early exit: missing tags
    if len(required_tags_missing) > 0:
        return _phase16f_no_go(
            check_id, ts_str, git_section, required_tags,
            _PHASE16F_DIAGNOSIS["missing_required_tags"],
            [f"Missing tags: {', '.join(required_tags_missing)}"],
        )

    # Early exit: dirty worktree
    if not git_section.get("worktree_clean", False) and git_section.get("worktree_clean") is not None:
        return _phase16f_no_go(
            check_id, ts_str, git_section, required_tags,
            _PHASE16F_DIAGNOSIS["dirty_worktree"],
            ["Commit or stash dirty files"] + [f"  {f}" for f in git_section.get("dirty_files", [])[:5]],
        )

    # ------------------------------------------------------------------
    # 3. Bridge runtime
    # ------------------------------------------------------------------
    br_reachable = False
    br_connected = False
    br_mode = "?"
    br_read_only = False
    ep_ok = 0
    ep_display = "?"
    try:
        req = urllib.request.Request(f"{BRIDGE_URL}/health", method="GET")
        with urllib.request.urlopen(req, timeout=8) as resp:
            if resp.status == 200:
                br_reachable = True
                hd = _json.loads(resp.read().decode())
                br_connected = hd.get("connected", False)
                br_mode = hd.get("mode", "?")
                br_read_only = br_mode == "paper"
    except Exception:
        pass

    # Endpoints
    snapshot_used = False
    if br_reachable:
        try:
            req = urllib.request.Request(f"{BRIDGE_URL}/snapshot", method="GET")
            with urllib.request.urlopen(req, timeout=8) as resp:
                if resp.status == 200:
                    snapshot_used = True
                    ep_ok = 7
                    ep_display = f"{ep_ok}/7 OK (snapshot)"
        except Exception:
            pass

    if not snapshot_used and br_reachable:
        _EPS = ["/health", "/readiness", "/status", "/monitor/reconciliation",
                "/monitor/alerts", "/monitor/events", "/positions", "/account"]
        ep_total = len(_EPS)
        for ep in _EPS:
            try:
                req = urllib.request.Request(f"{BRIDGE_URL}{ep}", method="GET")
                with urllib.request.urlopen(req, timeout=5) as resp:
                    if resp.status == 200:
                        ep_ok += 1
            except Exception:
                pass
        ep_display = f"{ep_ok}/{len(_EPS)} OK"

    # Positions
    positions_count = 0
    positions_flat = True
    if br_reachable:
        try:
            req = urllib.request.Request(f"{BRIDGE_URL}/positions", method="GET")
            with urllib.request.urlopen(req, timeout=8) as resp:
                if resp.status == 200:
                    pd = _json.loads(resp.read().decode())
                    pl = pd.get("positions", [])
                    positions_count = len(pl)
                    positions_flat = all(abs(p.get("position", 0)) < 0.01 for p in pl)
        except Exception:
            pass

    # Alerts
    active_alerts_count = 0
    if br_reachable:
        try:
            req = urllib.request.Request(f"{BRIDGE_URL}/monitor/alerts", method="GET")
            with urllib.request.urlopen(req, timeout=8) as resp:
                if resp.status == 200:
                    ad = _json.loads(resp.read().decode())
                    all_a = ad.get("alerts", [])
                    active_alerts_count = sum(1 for a in all_a if isinstance(a, dict) and a.get("requires_action", False))
        except Exception:
            pass

    runtime_section = {
        "bridge_reachable": br_reachable,
        "bridge_connected": br_connected,
        "mode": br_mode,
        "read_only": br_read_only,
        "endpoints_display": ep_display,
        "endpoints_ok": ep_ok,
        "positions_count": positions_count,
        "positions_flat": positions_flat,
        "active_alerts_count": active_alerts_count,
    }

    # ------------------------------------------------------------------
    # 4. Safety flags
    # ------------------------------------------------------------------
    env_safety = _read_env_safety(BRIDGE_DIR / ".env")
    rules_state = _read_rules_enforced(
        Path.home() / ".openclaw" / "risk-rules" / "paper-trading-rules.yaml"
    )
    autonomy_path = BRIDGE_DIR / "docs" / "AUTONOMY_CRITERIA.md"
    autonomy_level = _read_autonomy_level(autonomy_path)

    env_allow_orders = env_safety.get("IBKR_ALLOW_ORDERS", "?")
    rules_enforced = rules_state.get("enforced", "?")
    system_locked = True
    if br_reachable:
        try:
            req = urllib.request.Request(f"{BRIDGE_URL}/readiness", method="GET")
            with urllib.request.urlopen(req, timeout=5) as resp:
                if resp.status == 200:
                    rd = _json.loads(resp.read().decode())
                    system_locked = rd.get("summary", {}).get("kill_switches", {}).get("system_locked", True)
        except Exception:
            pass

    safety_section = {
        "env_IBKR_ALLOW_ORDERS": env_allow_orders,
        "rules_enforced": rules_enforced,
        "system_locked": system_locked,
    }

    # ------------------------------------------------------------------
    # 5. Guard state
    # ------------------------------------------------------------------
    try:
        from guard import canonical_trade_date as _canon
    except Exception:
        def _canon(dt):
            return dt.strftime("%Y-%m-%d")

    gs_assessment = _assess_guard_state_cleanliness(now_utc)
    g_count = gs_assessment["daily_trade_count"]
    g_date = gs_assessment["trade_date"]
    g_stale = gs_assessment["trade_date_stale"]
    g_hash = gs_assessment["guard_hash"]
    guard_section = gs_assessment["guard_section"]

    # ------------------------------------------------------------------
    # 6. Doctor / KPI / Policy
    # ------------------------------------------------------------------
    doctor_section: dict = {}
    try:
        dr = run_doctor()
        doc_pass = dr.get("passed", 0)
        doc_total = dr.get("total", 0)
        doctor_ok = dr.get("pass", False)
        doc_h1_status = "?"
        for c in dr.get("checks", []):
            if c.get("check") == "h1_token_canary":
                if c.get("status") == "MANUAL_REQUIRED":
                    doc_h1_status = "MANUAL_REQUIRED"
                elif c.get("ok"):
                    doc_h1_status = "PASS"
                else:
                    doc_h1_status = "FAIL"
                break
        doc_acceptable = doctor_ok or (
            doc_h1_status == "MANUAL_REQUIRED" and doc_pass >= doc_total - 1
        )
        doctor_section = {
            "result": "PASS" if doctor_ok else ("PASS_WITH_H1_MANUAL" if doc_acceptable else "FAIL"),
            "h1_canary_status": doc_h1_status,
            "acceptable": doc_acceptable,
        }
    except Exception as e:
        doctor_section = {"result": "ERROR", "h1_canary_status": "ERROR", "acceptable": False, "error": str(e)[:200]}

    kpi_section: dict = {}
    kpi_clean_cycles: int | None = None
    try:
        kpi_result = run_kpi()
        kpi_verdict = kpi_result.get("verdict", "ERROR")
        kpi_blockers = kpi_result.get("blockers", [])
        no_go_blockers = [b for b in kpi_blockers if b.get("severity") == "NO-GO"]
        kpi_acceptable_hold = (
            kpi_verdict == "HOLD" and len(no_go_blockers) == 0
            and any(b.get("check") in ("autonomy_level_zero", "system_locked")
                    for b in kpi_blockers if b.get("severity") == "HOLD")
        )
        # Extract clean_cycles from KPI result
        au = kpi_result.get("autonomy", {})
        if isinstance(au, dict):
            kpi_clean_cycles = au.get("clean_cycles")
            if kpi_clean_cycles is None:
                kpi_clean_cycles = kpi_result.get("clean_cycles")
        if kpi_clean_cycles is None:
            kpi_clean_cycles = kpi_result.get("clean_cycles")
        kpi_section = {
            "verdict": kpi_verdict,
            "blockers": [b.get("check", "?") for b in kpi_blockers],
            "acceptable_hold": kpi_acceptable_hold,
        }
    except Exception as e:
        kpi_section = {"verdict": "ERROR", "blockers": [], "acceptable_hold": False, "error": str(e)[:200]}

    policy_result = _check_hermes_policy()
    policy_section = {
        "hermes_policy_exists": policy_result["hermes_policy_exists"],
        "advisory_boundary_ok": policy_result["advisory_boundary_ok"],
        "execution_path_ok": policy_result["execution_path_ok"],
    }

    # ------------------------------------------------------------------
    # 7. Clean-cycles — canonical source (same as KPI)
    # ------------------------------------------------------------------
    canonical_ledger_path = OPENCLAW_DIR / "autonomy-cycles" / "clean-cycle-ledger.jsonl"
    clean_cycles_source = "openclaw_clean_cycle_ledger"
    drill_clean_cycles: int | None = None
    clean_cycles_defaulted_to_zero = False
    try:
        if canonical_ledger_path.exists():
            drill_clean_cycles = _count_clean_cycles(OPENCLAW_DIR)
        # else: stays None — explicitly unknown, not defaulted to 0
    except Exception:
        drill_clean_cycles = None

    # Detect if drill previously defaulted to 0 when unknown
    # (the bug: calling non-existent _read_ledger and catching the error)
    # We check if drill_clean_cycles is 0 but the ledger has entries
    if drill_clean_cycles == 0 and canonical_ledger_path.exists():
        # Check if ledger has any lines
        try:
            with open(canonical_ledger_path, "r", encoding="utf-8") as f:
                line_count = sum(1 for line in f if line.strip())
            if line_count > 0:
                clean_cycles_defaulted_to_zero = True
        except Exception:
            pass

    # Compute match
    clean_cycles_matches_kpi = False
    if kpi_clean_cycles is not None and drill_clean_cycles is not None:
        clean_cycles_matches_kpi = (kpi_clean_cycles == drill_clean_cycles)
    elif kpi_clean_cycles is None and drill_clean_cycles is None:
        clean_cycles_matches_kpi = True  # both unknown

    # ------------------------------------------------------------------
    # 8. Normalization summary
    # ------------------------------------------------------------------
    evidence_normalized = clean_cycles_matches_kpi and not clean_cycles_defaulted_to_zero
    clean_cycle_consistency_ok = clean_cycles_matches_kpi
    stability_drill_source_corrected = True  # drill now uses canonical source
    unknown_clean_cycles_reported_as_null = (drill_clean_cycles is None and not canonical_ledger_path.exists())

    normalization_summary = {
        "evidence_normalized": evidence_normalized,
        "clean_cycle_consistency_ok": clean_cycle_consistency_ok,
        "stability_drill_source_corrected": stability_drill_source_corrected,
        "unknown_clean_cycles_reported_as_null": unknown_clean_cycles_reported_as_null,
    }

    autonomy_section = {
        "current_level": autonomy_level,
        "clean_cycles": drill_clean_cycles,
        "clean_cycles_source": clean_cycles_source,
        "clean_cycles_matches_kpi": clean_cycles_matches_kpi,
        "kpi_clean_cycles": kpi_clean_cycles,
        "drill_clean_cycles": drill_clean_cycles,
    }

    # ------------------------------------------------------------------
    # 9. Classification
    # ------------------------------------------------------------------
    all_tags_present = len(required_tags_missing) == 0
    worktree_clean = git_section.get("worktree_clean", False)
    run_time_ready = br_connected and br_mode == "paper" and br_read_only
    safety_locked = env_allow_orders in ("false", "?") and rules_enforced in ("false", "?") and system_locked is True

    if not all_tags_present:
        diagnosis = _PHASE16F_DIAGNOSIS["missing_required_tags"]
        severity = "NO_GO"
    elif not worktree_clean and worktree_clean is not None:
        diagnosis = _PHASE16F_DIAGNOSIS["dirty_worktree"]
        severity = "NO_GO"
    elif not positions_flat and positions_count > 0:
        diagnosis = _PHASE16F_DIAGNOSIS["positions_not_flat"]
        severity = "NO_GO"
    elif active_alerts_count > 0:
        diagnosis = _PHASE16F_DIAGNOSIS["monitor_alerts_active"]
        severity = "NO_GO"
    elif not run_time_ready:
        diagnosis = _PHASE16F_DIAGNOSIS["runtime_not_ready"]
        severity = "HOLD" if not br_connected else "NO_GO"
    elif not safety_locked:
        diagnosis = _PHASE16F_DIAGNOSIS["safety_not_locked"]
        severity = "NO_GO"
    elif autonomy_level != "1":
        diagnosis = _PHASE16F_DIAGNOSIS["autonomy_not_level1"]
        severity = "NO_GO"
    elif g_count != 0 or g_stale or gs_assessment["halt_active"] is not False:
        diagnosis = _PHASE16F_DIAGNOSIS["guard_state_not_clean"]
        severity = "NO_GO"
    elif not doc_acceptable:
        diagnosis = _PHASE16F_DIAGNOSIS["doctor_not_acceptable"]
        severity = "NO_GO"
    elif not kpi_acceptable_hold:
        diagnosis = _PHASE16F_DIAGNOSIS["kpi_not_acceptable"]
        severity = "NO_GO"
    elif not policy_result["hermes_policy_exists"] or not policy_result["execution_path_ok"]:
        diagnosis = _PHASE16F_DIAGNOSIS["policy_boundary_missing"]
        severity = "NO_GO"
    elif clean_cycles_defaulted_to_zero:
        diagnosis = _PHASE16F_DIAGNOSIS["clean_cycles_defaulted_to_zero"]
        severity = "NO_GO"
    elif not clean_cycles_matches_kpi:
        diagnosis = _PHASE16F_DIAGNOSIS["clean_cycles_mismatch"]
        severity = "NO_GO"
    else:
        diagnosis = _PHASE16F_DIAGNOSIS["ready"]
        severity = "OK"

    check_ok = diagnosis == _PHASE16F_DIAGNOSIS["ready"]
    operator_action_required = not check_ok
    suggested_actions: list[str] = []
    if not check_ok:
        suggested_actions.append(f"Evidence normalization check failed: {diagnosis}")
        if not clean_cycles_matches_kpi:
            suggested_actions.append(f"KPI clean_cycles={kpi_clean_cycles} != drill clean_cycles={drill_clean_cycles}")
        if clean_cycles_defaulted_to_zero:
            suggested_actions.append("Drill clean_cycles defaulted to 0 when ledger has entries — source bug")

    # ------------------------------------------------------------------
    # 10. Evidence hash
    # ------------------------------------------------------------------
    hashable = {
        "diagnosis": diagnosis, "severity": severity,
        "clean_cycles_matches_kpi": clean_cycles_matches_kpi,
        "kpi_clean_cycles": kpi_clean_cycles,
        "drill_clean_cycles": drill_clean_cycles,
        "no_broker_mutation": True,
    }
    evidence_hash = _compute_evidence_hash(hashable)

    # ------------------------------------------------------------------
    # 11. Assemble result
    # ------------------------------------------------------------------
    result: dict[str, Any] = {
        "command": "ibkr-operator level1-evidence-normalization-check",
        "advisory": (
            "Read-only Level 1 evidence normalization / clean-cycle consistency check (Phase 16F). "
            "Compares KPI clean_cycles against the canonical openclaw_clean_cycle_ledger source. "
            "No orders. No mutations. No H1 token. No broker activity. "
            "No autonomy level change."
        ),
        "timestamp": ts_str,
        "check_id": check_id,
        "diagnosis": diagnosis,
        "severity": severity,
        "operator_action_required": operator_action_required,
        "suggested_operator_actions": suggested_actions,
        "git": git_section,
        "required_tags": required_tags,
        "runtime": runtime_section,
        "autonomy": autonomy_section,
        "safety": safety_section,
        "guard_state": guard_section,
        "normalization_summary": normalization_summary,
        "kpi_summary": kpi_section,
        "doctor_summary": doctor_section,
        "policy_summary": policy_section,
        "promotion_allowed_now": False,
        "order_enablement_allowed_now": False,
        "order_enablement_performed": False,
        "promotion_performed": False,
        "no_broker_mutation": True,
        "no_order_window_opened": True,
        "h1_token_not_used": True,
        "evidence_hash": evidence_hash,
        "explicit_non_actions": _PHASE16F_EXPLICIT_NON_ACTIONS,
    }

    _PHASE16F_EXPORT_DIR.mkdir(parents=True, exist_ok=True)
    export_path = _PHASE16F_EXPORT_DIR / f"{check_id}.json"
    try:
        tmp = export_path.with_suffix(".tmp")
        with open(tmp, "w", encoding="utf-8") as f:
            _json.dump(result, f, indent=2, default=str, ensure_ascii=False)
            f.flush()
            os.fsync(f.fileno())
        os.replace(tmp, export_path)
        result["export_path"] = str(export_path)
        result["_export_path"] = str(export_path)
    except Exception as e:
        result["_export_error"] = str(e)[:200]
        result["export_path"] = None

    return result


def _phase16f_no_go(
    check_id: str, ts_str: str, git_section: dict, required_tags: dict,
    diagnosis: str, actions: list,
) -> dict:
    """Build a NO_GO result for early-exit prerequisite failures."""
    return {
        "command": "ibkr-operator level1-evidence-normalization-check",
        "timestamp": ts_str,
        "check_id": check_id,
        "diagnosis": diagnosis,
        "severity": "NO_GO",
        "operator_action_required": True,
        "suggested_operator_actions": actions,
        "git": git_section,
        "required_tags": required_tags,
        "runtime": {},
        "autonomy": {},
        "safety": {},
        "guard_state": {},
        "normalization_summary": {},
        "kpi_summary": {},
        "doctor_summary": {},
        "policy_summary": {},
        "promotion_allowed_now": False,
        "order_enablement_allowed_now": False,
        "order_enablement_performed": False,
        "promotion_performed": False,
        "no_broker_mutation": True,
        "no_order_window_opened": True,
        "h1_token_not_used": True,
        "evidence_hash": _compute_evidence_hash({"diagnosis": diagnosis}),
        "explicit_non_actions": _PHASE16F_EXPLICIT_NON_ACTIONS,
    }


def _print_level1_evidence_normalization_check(result: dict) -> None:
    """Print Phase 16F evidence normalization check in human-readable format."""
    check_ok = result.get("diagnosis") == _PHASE16F_DIAGNOSIS["ready"]
    diag_color = GREEN if check_ok else RED
    sev = result.get("severity", "?")
    sev_color = GREEN if sev == "OK" else (YELLOW if sev == "HOLD" else RED)

    print(f"{BOLD}══════════════════════════════════════════════════{RESET}")
    print(f"{BOLD}  Level 1 Evidence Normalization Check (16F){RESET}")
    print(f"{BOLD}══════════════════════════════════════════════════{RESET}\n")
    print(f"  Check ID:        {result.get('check_id', '?')}")
    print(f"  Timestamp:       {result.get('timestamp', '?')}")
    print(f"  Diagnosis:       {diag_color}{result.get('diagnosis', '?')}{RESET}")
    print(f"  Severity:        {sev_color}{sev}{RESET}")
    print()

    auto = result.get("autonomy", {})
    if auto:
        print(f"  {BOLD}Autonomy{RESET}")
        print(f"    Current Level:          {auto.get('current_level', '?')}")
        cc = auto.get('clean_cycles')
        cc_display = str(cc) if cc is not None else "null (unknown)"
        print(f"    Clean Cycles:           {cc_display}")
        print(f"    Source:                 {auto.get('clean_cycles_source', '?')}")
        match_ok = auto.get('clean_cycles_matches_kpi')
        print(f"    Matches KPI:            {GREEN if match_ok else RED}{match_ok}{RESET}")
        print(f"    KPI clean_cycles:       {auto.get('kpi_clean_cycles', '?')}")
        print()

    safety = result.get("safety", {})
    if safety:
        print(f"  {BOLD}Safety{RESET}")
        print(f"    IBKR_ALLOW_ORDERS:      {safety.get('env_IBKR_ALLOW_ORDERS', '?')}")
        print(f"    rules.enforced:         {safety.get('rules_enforced', '?')}")
        print(f"    system_locked:          {_bool_str(safety.get('system_locked'))}")
        print()

    ns = result.get("normalization_summary", {})
    if ns:
        print(f"  {BOLD}Normalization Summary{RESET}")
        for key, val in ns.items():
            color = GREEN if val else RED
            print(f"    {key:<42} {color}{val}{RESET}")
        print()

    runtime = result.get("runtime", {})
    if runtime:
        print(f"  {BOLD}Runtime{RESET}")
        print(f"    Bridge:         connected={_bool_str(runtime.get('bridge_connected'))} mode={runtime.get('mode', '?')}")
        print(f"    Endpoints:      {runtime.get('endpoints_display', '?')}")
        print(f"    Positions:      {runtime.get('positions_count', 0)}  flat={_bool_str(runtime.get('positions_flat'))}")
        print(f"    Alerts:         {runtime.get('active_alerts_count', 0)}")
        print()

    guard = result.get("guard_state", {})
    if guard:
        print(f"  {BOLD}Guard State{RESET}")
        print(f"    Trade count:    {guard.get('daily_trade_count', '?')}")
        print(f"    Trade date:     {guard.get('trade_date', '?')}")
        print(f"    Canonical:      {guard.get('canonical_trade_date', '?')}")
        print(f"    Stale:          {_bool_str(guard.get('trade_date_stale'))}")
        print()

    sa = result.get("suggested_operator_actions", [])
    if sa:
        print(f"  {BOLD}Suggested Actions{RESET}")
        for a in sa:
            print(f"    {YELLOW}→{RESET} {a}")
        print()

    print(f"  {BOLD}Advisory{RESET}")
    print(f"    {result.get('advisory', '')}")

    eh = result.get("evidence_hash", "")
    if eh:
        print(f"\n  Evidence hash: {eh[:16]}...")

    ep = result.get("export_path") or result.get("_export_path")
    if ep:
        print(f"  Export: {ep}")
    print()


# ===========================================================================
# Phase 16G — Level 1 Proposal-Only Workflow Drill
# ===========================================================================

def _run_level1_proposal_workflow_drill(
    demo_candidates: int = 2,
    proposal_source: str = "synthetic_readonly_demo",
) -> dict:
    """Run Level 1 proposal-only workflow drill (Phase 16G).

    Read-only drill proving Werner/operator can prepare proposal batches
    for Chris review without enabling orders, opening an order window,
    using H1, or calling any order endpoint.
    """
    import hashlib
    import json as _json
    import subprocess as _sp
    import urllib.request
    import urllib.error
    from datetime import datetime, timezone
    from typing import Any

    now_utc = datetime.now(timezone.utc)
    ts_str = now_utc.strftime("%Y-%m-%dT%H:%M:%SZ")
    ts_file = now_utc.strftime("%Y%m%dT%H%M%SZ")
    drill_id = f"proposal-drill-{ts_file}"
    effective_candidates = max(0, min(demo_candidates, 5))

    # ------------------------------------------------------------------
    # 1. Git / worktree
    # ------------------------------------------------------------------
    git = _git_metadata(BRIDGE_DIR)
    full_commit = git.get("commit_short", "?")
    try:
        p = _sp.run(
            ["git", "-C", str(BRIDGE_DIR), "rev-parse", "HEAD"],
            capture_output=True, text=True, timeout=5,
        )
        if p.stdout.strip():
            full_commit = p.stdout.strip()
    except Exception:
        pass

    worktree = _get_worktree_state(BRIDGE_DIR)
    origin_alignment = _get_origin_master_alignment(BRIDGE_DIR)

    git_section = {
        "branch": git.get("branch", "?"),
        "commit": full_commit if len(full_commit) > 16 else git.get("commit_short", "?"),
        "commit_short": git.get("commit_short", "?"),
        "tag": git.get("tag", "?"),
        "origin_master_commit": origin_alignment.get("origin_master_commit", "?"),
        "origin_master_aligned": origin_alignment.get("aligned"),
        "worktree_clean": worktree.get("clean"),
        "dirty_files": worktree.get("dirty_files", []),
    }

    # ------------------------------------------------------------------
    # 2. Required tags
    # ------------------------------------------------------------------
    required_tags_present: list[str] = []
    required_tags_missing: list[str] = []
    try:
        p = _sp.run(
            ["git", "-C", str(BRIDGE_DIR), "tag"],
            capture_output=True, text=True, timeout=10,
        )
        all_tags = set(p.stdout.strip().splitlines())
        for tag in _PHASE16G_REQUIRED_TAGS:
            if tag in all_tags:
                required_tags_present.append(tag)
            else:
                required_tags_missing.append(tag)
    except Exception:
        required_tags_missing = list(_PHASE16G_REQUIRED_TAGS)
        required_tags_present = []

    required_tags = {
        "required_count": len(_PHASE16G_REQUIRED_TAGS),
        "present_count": len(required_tags_present),
        "missing": required_tags_missing,
        "present": required_tags_present,
    }

    # Early exit: missing tags
    if len(required_tags_missing) > 0:
        return _phase16g_no_go(
            drill_id, ts_str, git_section, required_tags,
            _PHASE16G_DIAGNOSIS["missing_required_tags"],
            [f"Missing tags: {', '.join(required_tags_missing)}"],
        )

    # Early exit: dirty worktree
    if not git_section.get("worktree_clean", False) and git_section.get("worktree_clean") is not None:
        return _phase16g_no_go(
            drill_id, ts_str, git_section, required_tags,
            _PHASE16G_DIAGNOSIS["dirty_worktree"],
            ["Commit or stash dirty files"] + [f"  {f}" for f in git_section.get("dirty_files", [])[:5]],
        )

    # ------------------------------------------------------------------
    # 3. Bridge runtime
    # ------------------------------------------------------------------
    br_reachable = False
    br_connected = False
    br_mode = "?"
    br_read_only = False
    ep_ok = 0
    ep_display = "?"
    try:
        req = urllib.request.Request(f"{BRIDGE_URL}/health", method="GET")
        with urllib.request.urlopen(req, timeout=8) as resp:
            if resp.status == 200:
                br_reachable = True
                hd = _json.loads(resp.read().decode())
                br_connected = hd.get("connected", False)
                br_mode = hd.get("mode", "?")
                br_read_only = br_mode == "paper"
    except Exception:
        pass

    # Endpoints
    snapshot_used = False
    if br_reachable:
        try:
            req = urllib.request.Request(f"{BRIDGE_URL}/snapshot", method="GET")
            with urllib.request.urlopen(req, timeout=8) as resp:
                if resp.status == 200:
                    snapshot_used = True
                    ep_ok = 7
                    ep_display = f"{ep_ok}/7 OK (snapshot)"
        except Exception:
            pass

    if not snapshot_used and br_reachable:
        _EPS = ["/health", "/readiness", "/status", "/monitor/reconciliation",
                "/monitor/alerts", "/monitor/events", "/positions", "/account"]
        for ep in _EPS:
            try:
                req = urllib.request.Request(f"{BRIDGE_URL}{ep}", method="GET")
                with urllib.request.urlopen(req, timeout=5) as resp:
                    if resp.status == 200:
                        ep_ok += 1
            except Exception:
                pass
        ep_display = f"{ep_ok}/{len(_EPS)} OK"

    # Positions
    positions_count = 0
    positions_flat = True
    if br_reachable:
        try:
            req = urllib.request.Request(f"{BRIDGE_URL}/positions", method="GET")
            with urllib.request.urlopen(req, timeout=8) as resp:
                if resp.status == 200:
                    pd = _json.loads(resp.read().decode())
                    pl = pd.get("positions", [])
                    positions_count = len(pl)
                    positions_flat = all(abs(p.get("position", 0)) < 0.01 for p in pl)
        except Exception:
            pass

    # Alerts
    active_alerts_count = 0
    if br_reachable:
        try:
            req = urllib.request.Request(f"{BRIDGE_URL}/monitor/alerts", method="GET")
            with urllib.request.urlopen(req, timeout=8) as resp:
                if resp.status == 200:
                    ad = _json.loads(resp.read().decode())
                    all_a = ad.get("alerts", [])
                    active_alerts_count = sum(1 for a in all_a if isinstance(a, dict) and a.get("requires_action", False))
        except Exception:
            pass

    runtime_section = {
        "bridge_reachable": br_reachable,
        "bridge_connected": br_connected,
        "mode": br_mode,
        "read_only": br_read_only,
        "endpoints_display": ep_display,
        "endpoints_ok": ep_ok,
        "positions_count": positions_count,
        "positions_flat": positions_flat,
        "active_alerts_count": active_alerts_count,
    }

    # ------------------------------------------------------------------
    # 4. Safety flags
    # ------------------------------------------------------------------
    env_safety = _read_env_safety(BRIDGE_DIR / ".env")
    rules_state = _read_rules_enforced(
        Path.home() / ".openclaw" / "risk-rules" / "paper-trading-rules.yaml"
    )
    autonomy_path = BRIDGE_DIR / "docs" / "AUTONOMY_CRITERIA.md"
    autonomy_level = _read_autonomy_level(autonomy_path)

    env_allow_orders = env_safety.get("IBKR_ALLOW_ORDERS", "?")
    rules_enforced = rules_state.get("enforced", "?")
    system_locked = True
    if br_reachable:
        try:
            req = urllib.request.Request(f"{BRIDGE_URL}/readiness", method="GET")
            with urllib.request.urlopen(req, timeout=5) as resp:
                if resp.status == 200:
                    rd = _json.loads(resp.read().decode())
                    system_locked = rd.get("summary", {}).get("kill_switches", {}).get("system_locked", True)
        except Exception:
            pass

    safety_section = {
        "env_IBKR_ALLOW_ORDERS": env_allow_orders,
        "rules_enforced": rules_enforced,
        "system_locked": system_locked,
    }

    # ------------------------------------------------------------------
    # 5. Guard state — centralized assessor
    # ------------------------------------------------------------------
    gs_assessment = _assess_guard_state_cleanliness(now_utc)
    guard_section = gs_assessment["guard_section"]

    # ------------------------------------------------------------------
    # 6. Doctor / KPI / Policy
    # ------------------------------------------------------------------
    doctor_section: dict = {}
    try:
        dr = run_doctor()
        doc_pass = dr.get("passed", 0)
        doc_total = dr.get("total", 0)
        doctor_ok = dr.get("pass", False)
        doc_h1_status = "?"
        for c in dr.get("checks", []):
            if c.get("check") == "h1_token_canary":
                if c.get("status") == "MANUAL_REQUIRED":
                    doc_h1_status = "MANUAL_REQUIRED"
                elif c.get("ok"):
                    doc_h1_status = "PASS"
                else:
                    doc_h1_status = "FAIL"
                break
        doc_acceptable = doctor_ok or (
            doc_h1_status == "MANUAL_REQUIRED" and doc_pass >= doc_total - 1
        )
        doctor_section = {
            "result": "PASS" if doctor_ok else ("PASS_WITH_H1_MANUAL" if doc_acceptable else "FAIL"),
            "h1_canary_status": doc_h1_status,
            "acceptable": doc_acceptable,
        }
    except Exception as e:
        doctor_section = {"result": "ERROR", "h1_canary_status": "ERROR", "acceptable": False, "error": str(e)[:200]}

    kpi_section: dict = {}
    kpi_clean_cycles: int | None = None
    try:
        kpi_result = run_kpi()
        kpi_verdict = kpi_result.get("verdict", "ERROR")
        kpi_blockers = kpi_result.get("blockers", [])
        no_go_blockers = [b for b in kpi_blockers if b.get("severity") == "NO-GO"]
        kpi_acceptable_hold = (
            kpi_verdict == "HOLD" and len(no_go_blockers) == 0
            and any(b.get("check") == "system_locked"
                    for b in kpi_blockers if b.get("severity") == "HOLD")
        )
        au = kpi_result.get("autonomy", {})
        if isinstance(au, dict):
            kpi_clean_cycles = au.get("clean_cycles")
            if kpi_clean_cycles is None:
                kpi_clean_cycles = kpi_result.get("clean_cycles")
        if kpi_clean_cycles is None:
            kpi_clean_cycles = kpi_result.get("clean_cycles")
        kpi_section = {
            "verdict": kpi_verdict,
            "blockers": [b.get("check", "?") for b in kpi_blockers],
            "acceptable_hold": kpi_acceptable_hold,
        }
    except Exception as e:
        kpi_section = {"verdict": "ERROR", "blockers": [], "acceptable_hold": False, "error": str(e)[:200]}

    policy_result = _check_hermes_policy()
    policy_section = {
        "hermes_policy_exists": policy_result["hermes_policy_exists"],
        "advisory_boundary_ok": policy_result["advisory_boundary_ok"],
        "execution_path_ok": policy_result["execution_path_ok"],
    }

    # ------------------------------------------------------------------
    # 7. Clean-cycles — canonical source
    # ------------------------------------------------------------------
    canonical_ledger_path = OPENCLAW_DIR / "autonomy-cycles" / "clean-cycle-ledger.jsonl"
    clean_cycles_source = "openclaw_clean_cycle_ledger"
    drill_clean_cycles: int | None = None
    try:
        if canonical_ledger_path.exists():
            drill_clean_cycles = _count_clean_cycles(OPENCLAW_DIR)
    except Exception:
        drill_clean_cycles = None

    clean_cycles_matches_kpi = False
    if kpi_clean_cycles is not None and drill_clean_cycles is not None:
        clean_cycles_matches_kpi = (kpi_clean_cycles == drill_clean_cycles)
    elif kpi_clean_cycles is None and drill_clean_cycles is None:
        clean_cycles_matches_kpi = True

    autonomy_section = {
        "current_level": autonomy_level,
        "clean_cycles": drill_clean_cycles,
        "clean_cycles_source": clean_cycles_source,
        "clean_cycles_matches_kpi": clean_cycles_matches_kpi,
    }

    # ------------------------------------------------------------------
    # 8. Generate proposal batch (read-only synthetic demo)
    # ------------------------------------------------------------------
    proposals_created = 0
    proposal_items: list[dict[str, Any]] = []
    proposal_ids: list[str] = []
    import uuid

    for i in range(min(effective_candidates, len(_PROPOSAL_SYMBOL_POOL))):
        candidate = _PROPOSAL_SYMBOL_POOL[i]
        pid = f"proposal-{drill_id}-{i+1:03d}"
        quantity = (i + 1) * 10  # synthetic quantities: 10, 20, 30, ...
        item: dict[str, Any] = {
            "proposal_id": pid,
            "source": proposal_source,
            "symbol": candidate["symbol"],
            "side": candidate["side"],
            "quantity": quantity,
            "rationale": candidate["rationale"],
            "risk_notes": f"Synthetic demo proposal — not executable. Max position size: {quantity} shares. "
                          f"Requires Chris review before any order path.",
            "executable": False,
            "requires_chris_approval": True,
            "future_required_path": "/order/preflight -> /order/approve -> /order/submit",
            "performed": False,
        }
        proposal_items.append(item)
        proposal_ids.append(pid)
        proposals_created += 1

    batch_id = f"proposal-batch-{ts_file}"
    proposal_batch: dict[str, Any] = {
        "batch_id": batch_id,
        "status": "review_only",
        "items": proposal_items,
    }

    proposal_workflow = {
        "proposal_only": True,
        "proposal_source": proposal_source,
        "demo_candidates_requested": effective_candidates,
        "candidates_examined": effective_candidates,
        "proposals_created": proposals_created,
        "proposals_marked_executable": False,
        "proposals_require_chris_review": True,
        "human_approval_required": True,
        "h1_required_for_future_submit": True,
        "order_window_required_for_future_submit": True,
        "order_routing_disallowed": True,
        "broker_submission_performed": False,
        "preflight_performed": False,
        "approval_performed": False,
        "submit_performed": False,
    }

    workflow_summary = {
        "level1_proposal_workflow_ready": True,
        "proposal_batch_created": proposals_created > 0,
        "all_items_non_executable": all(not it.get("executable", True) for it in proposal_items),
        "all_items_require_human_approval": all(it.get("requires_chris_approval", True) for it in proposal_items),
        "no_order_path_called": True,
        "no_broker_submission": True,
        "no_h1_seen": True,
        "no_order_window_seen": True,
    }

    # ------------------------------------------------------------------
    # 9. Classification
    # ------------------------------------------------------------------
    all_tags_present = len(required_tags_missing) == 0
    worktree_clean = git_section.get("worktree_clean", False)
    run_time_ready = br_connected and br_mode == "paper" and br_read_only
    safety_locked = env_allow_orders in ("false", "?") and rules_enforced in ("false", "?") and system_locked is True

    if not all_tags_present:
        diagnosis = _PHASE16G_DIAGNOSIS["missing_required_tags"]
        severity = "NO_GO"
    elif not worktree_clean and worktree_clean is not None:
        diagnosis = _PHASE16G_DIAGNOSIS["dirty_worktree"]
        severity = "NO_GO"
    elif not positions_flat and positions_count > 0:
        diagnosis = _PHASE16G_DIAGNOSIS["positions_not_flat"]
        severity = "NO_GO"
    elif active_alerts_count > 0:
        diagnosis = _PHASE16G_DIAGNOSIS["monitor_alerts_active"]
        severity = "NO_GO"
    elif not run_time_ready:
        diagnosis = _PHASE16G_DIAGNOSIS["runtime_not_ready"]
        severity = "HOLD" if not br_connected else "NO_GO"
    elif not safety_locked:
        diagnosis = _PHASE16G_DIAGNOSIS["safety_not_locked"]
        severity = "NO_GO"
    elif autonomy_level != "1":
        diagnosis = _PHASE16G_DIAGNOSIS["autonomy_not_level1"]
        severity = "NO_GO"
    elif not gs_assessment["guard_state_clean"]:
        diagnosis = _PHASE16G_DIAGNOSIS["guard_state_not_clean"]
        severity = "NO_GO"
    elif not doc_acceptable:
        diagnosis = _PHASE16G_DIAGNOSIS["doctor_not_acceptable"]
        severity = "NO_GO"
    elif not kpi_acceptable_hold:
        diagnosis = _PHASE16G_DIAGNOSIS["kpi_not_acceptable"]
        severity = "NO_GO"
    elif not policy_result["hermes_policy_exists"] or not policy_result["execution_path_ok"]:
        diagnosis = _PHASE16G_DIAGNOSIS["policy_boundary_missing"]
        severity = "NO_GO"
    elif not clean_cycles_matches_kpi:
        diagnosis = _PHASE16G_DIAGNOSIS["clean_cycles_mismatch"]
        severity = "NO_GO"
    else:
        diagnosis = _PHASE16G_DIAGNOSIS["ready"]
        severity = "OK"

    drill_ok = diagnosis == _PHASE16G_DIAGNOSIS["ready"]
    operator_action_required = not drill_ok
    suggested_actions: list[str] = []
    if not drill_ok:
        suggested_actions.append(f"Proposal workflow drill blocked: {diagnosis}")
        if not run_time_ready:
            suggested_actions.append("Ensure bridge is connected in paper read-only mode")
        if not safety_locked:
            suggested_actions.append("Verify all safety locks are engaged")
        if not gs_assessment["guard_state_clean"]:
            suggested_actions.append("Run guard-state-reconcile to fix guard state")

    # ------------------------------------------------------------------
    # 10. Evidence hash
    # ------------------------------------------------------------------
    hashable = {
        "diagnosis": diagnosis, "severity": severity,
        "proposals_created": proposals_created,
        "proposal_source": proposal_source,
        "no_broker_mutation": True,
        "no_order_window_opened": True,
    }
    evidence_hash = _compute_evidence_hash(hashable)

    # ------------------------------------------------------------------
    # 11. Assemble result
    # ------------------------------------------------------------------
    result: dict[str, Any] = {
        "command": "ibkr-operator level1-proposal-workflow-drill",
        "advisory": (
            "Read-only Level 1 proposal-only workflow drill (Phase 16G). "
            "Prepares proposal batches for Chris review. "
            "No orders. No mutations. No H1 token. No broker activity. "
            "No autonomy level change. All proposals are non-executable and require human approval."
        ),
        "timestamp": ts_str,
        "drill_id": drill_id,
        "diagnosis": diagnosis,
        "severity": severity,
        "operator_action_required": operator_action_required,
        "suggested_operator_actions": suggested_actions,
        "git": git_section,
        "required_tags": required_tags,
        "runtime": runtime_section,
        "autonomy": autonomy_section,
        "safety": safety_section,
        "guard_state": guard_section,
        "proposal_workflow": proposal_workflow,
        "proposal_batch": proposal_batch,
        "workflow_summary": workflow_summary,
        "kpi_summary": kpi_section,
        "doctor_summary": doctor_section,
        "policy_summary": policy_section,
        "promotion_allowed_now": False,
        "order_enablement_allowed_now": False,
        "order_enablement_performed": False,
        "promotion_performed": False,
        "no_broker_mutation": True,
        "no_order_window_opened": True,
        "no_order_window_seen": True,
        "no_h1_seen": True,
        "h1_token_not_used": True,
        "evidence_hash": evidence_hash,
        "explicit_non_actions": _PHASE16G_EXPLICIT_NON_ACTIONS,
    }

    # ------------------------------------------------------------------
    # 12. Export artifact
    # ------------------------------------------------------------------
    export_path: str | None = None
    try:
        _PHASE16G_EXPORT_DIR.mkdir(parents=True, exist_ok=True)
        ep = _PHASE16G_EXPORT_DIR / f"{drill_id}.json"
        with open(ep, "w", encoding="utf-8") as f:
            _json.dump(result, f, indent=2, default=str)
        export_path = str(ep)
    except Exception:
        pass

    result["export_path"] = export_path
    return result


def _phase16g_no_go(
    drill_id: str, ts_str: str, git_section: dict, required_tags: dict,
    diagnosis: str, actions: list,
) -> dict:
    """Build a NO_GO result for early-exit prerequisite failures."""
    return {
        "command": "ibkr-operator level1-proposal-workflow-drill",
        "timestamp": ts_str,
        "drill_id": drill_id,
        "diagnosis": diagnosis,
        "severity": "NO_GO",
        "operator_action_required": True,
        "suggested_operator_actions": actions,
        "git": git_section,
        "required_tags": required_tags,
        "runtime": {},
        "autonomy": {},
        "safety": {},
        "guard_state": {},
        "proposal_workflow": {},
        "proposal_batch": {"batch_id": drill_id, "status": "blocked", "items": []},
        "workflow_summary": {},
        "kpi_summary": {},
        "doctor_summary": {},
        "policy_summary": {},
        "promotion_allowed_now": False,
        "order_enablement_allowed_now": False,
        "order_enablement_performed": False,
        "promotion_performed": False,
        "no_broker_mutation": True,
        "no_order_window_opened": True,
        "no_order_window_seen": True,
        "no_h1_seen": True,
        "h1_token_not_used": True,
        "evidence_hash": _compute_evidence_hash({"diagnosis": diagnosis}),
        "explicit_non_actions": _PHASE16G_EXPLICIT_NON_ACTIONS,
    }


def _print_level1_proposal_workflow_drill(result: dict) -> None:
    """Print Phase 16G proposal workflow drill in human-readable format."""
    drill_ok = result.get("diagnosis") == _PHASE16G_DIAGNOSIS["ready"]
    diag_color = GREEN if drill_ok else RED
    sev = result.get("severity", "?")
    sev_color = GREEN if sev == "OK" else (YELLOW if sev == "HOLD" else RED)

    print(f"{BOLD}══════════════════════════════════════════════════{RESET}")
    print(f"{BOLD}  Level 1 Proposal-Only Workflow Drill (16G){RESET}")
    print(f"{BOLD}══════════════════════════════════════════════════{RESET}\n")
    print(f"  Drill ID:        {result.get('drill_id', '?')}")
    print(f"  Timestamp:       {result.get('timestamp', '?')}")
    print(f"  Diagnosis:       {diag_color}{result.get('diagnosis', '?')}{RESET}")
    print(f"  Severity:        {sev_color}{sev}{RESET}")
    print()

    pw = result.get("proposal_workflow", {})
    if pw:
        print(f"  {BOLD}Proposal Workflow{RESET}")
        print(f"    Proposal-only:          {pw.get('proposal_only')}")
        print(f"    Source:                 {pw.get('proposal_source', '?')}")
        print(f"    Candidates requested:   {pw.get('demo_candidates_requested', 0)}")
        print(f"    Proposals created:      {pw.get('proposals_created', 0)}")
        print(f"    Marked executable:      {RED}{pw.get('proposals_marked_executable')}{RESET}")
        print(f"    Requires Chris review:  {GREEN}{pw.get('proposals_require_chris_review')}{RESET}")
        print(f"    Broker submission:      {RED}{pw.get('broker_submission_performed')}{RESET}")
        print()

    wf = result.get("workflow_summary", {})
    if wf:
        print(f"  {BOLD}Workflow Summary{RESET}")
        for key, val in wf.items():
            color = GREEN if val else RED
            print(f"    {key:<42} {color}{val}{RESET}")
        print()

    pb = result.get("proposal_batch", {})
    if pb:
        print(f"  {BOLD}Proposal Batch{RESET}")
        print(f"    Batch ID:      {pb.get('batch_id', '?')}")
        print(f"    Status:        {pb.get('status', '?')}")
        items = pb.get("items", [])
        print(f"    Items:         {len(items)}")
        for item in items:
            side_color = GREEN if item.get('side') == 'BUY' else RED
            print(f"      {item.get('proposal_id', '?')}: {item.get('symbol', '?')} "
                  f"{side_color}{item.get('side', '?')}{RESET} "
                  f"qty={item.get('quantity', 0)} "
                  f"exec={RED}{item.get('executable')}{RESET}")
        print()

    auto = result.get("autonomy", {})
    if auto:
        print(f"  {BOLD}Autonomy{RESET}")
        print(f"    Level:          {auto.get('current_level', '?')}")
        cc = auto.get('clean_cycles')
        print(f"    Clean cycles:   {cc if cc is not None else 'null'}")
        print(f"    Matches KPI:    {auto.get('clean_cycles_matches_kpi')}")
        print()

    safety = result.get("safety", {})
    if safety:
        print(f"  {BOLD}Safety{RESET}")
        print(f"    ALLOW_ORDERS:   {safety.get('env_IBKR_ALLOW_ORDERS', '?')}")
        print(f"    rules.enforced: {safety.get('rules_enforced', '?')}")
        print(f"    system_locked:  {_bool_str(safety.get('system_locked'))}")
        print()

    runtime = result.get("runtime", {})
    if runtime:
        print(f"  {BOLD}Runtime{RESET}")
        print(f"    Bridge:         connected={_bool_str(runtime.get('bridge_connected'))} mode={runtime.get('mode', '?')}")
        print(f"    Endpoints:      {runtime.get('endpoints_display', '?')}")
        print(f"    Positions:      {runtime.get('positions_count', 0)}  flat={_bool_str(runtime.get('positions_flat'))}")
        print(f"    Alerts:         {runtime.get('active_alerts_count', 0)}")
        print()

    guard = result.get("guard_state", {})
    if guard:
        print(f"  {BOLD}Guard State{RESET}")
        print(f"    Trade count:    {guard.get('daily_trade_count', '?')}")
        print(f"    Trade date:     {guard.get('trade_date', '?')}")
        print(f"    Stale:          {_bool_str(guard.get('trade_date_stale'))}")
        print(f"    Clean:          {_bool_str(guard.get('guard_state_clean'))}")
        print()

    sa = result.get("suggested_operator_actions", [])
    if sa:
        print(f"  {BOLD}Suggested Actions{RESET}")
        for a in sa:
            print(f"    {YELLOW}→{RESET} {a}")
        print()

    print(f"  {BOLD}Advisory{RESET}")
    print(f"    {result.get('advisory', '')}")

    eh = result.get("evidence_hash", "")
    if eh:
        print(f"\n  Evidence hash: {eh[:16]}...")

    ep = result.get("export_path") or result.get("_export_path")
    if ep:
        print(f"  Export: {ep}")
    print()



# ===========================================================================
# Phase 16H — Level 1 Human Review Package Drill
# ===========================================================================

_PHASE16H_EXPORT_DIR = OPENCLAW_DIR / "level1-review-packages"

_PHASE16H_REQUIRED_TAGS: tuple[str, ...] = (
    "phase16g_level1_proposal_workflow_drill",
    "phase16f_level1_evidence_normalization",
    "phase16e_level1_post_promotion_stability_drill",
)

_PHASE16H_DIAGNOSIS = {
    "ready": "level1_human_review_package_ok",
    "missing_required_tags": "missing_required_tags",
    "dirty_worktree": "dirty_worktree",
    "autonomy_not_level1": "autonomy_not_level1",
    "runtime_not_ready": "runtime_not_ready",
    "safety_not_locked": "safety_not_locked",
    "guard_state_not_clean": "guard_state_not_clean",
    "positions_not_flat": "positions_not_flat",
    "monitor_alerts_active": "monitor_alerts_active",
    "doctor_not_acceptable": "doctor_not_acceptable",
    "kpi_not_acceptable": "kpi_not_acceptable",
    "policy_boundary_missing": "policy_boundary_missing",
    "clean_cycles_mismatch": "clean_cycles_mismatch",
    "executable_item_present": "executable_item_present",
    "unknown": "unknown",
}

_PHASE16H_EXPLICIT_NON_ACTIONS: list[str] = [
    "This command did not change autonomy level.",
    "This command did not enable orders.",
    "This command did not change IBKR_ALLOW_ORDERS.",
    "This command did not change rules.enforced.",
    "This command did not unlock system_locked.",
    "This command did not open an order window.",
    "This command did not read H1 token.",
    "This command did not call trade-window helper.",
    "This command did not call /order, /order/preflight, /order/approve, or /order/submit.",
    "This command did not submit orders.",
    "This command did not call broker mutation endpoints.",
    "This command did not restart bridge.",
    "This command did not reconnect automatically.",
    "This command did not repair guard-state.",
    "Only allowed writes are the export artifact and review package artifact.",
]

# Synthetic demo candidate pool for review package generation
_REVIEW_CANDIDATE_POOL: list[dict] = [
    {"symbol": "SPY", "side": "BUY", "rationale": "Core S&P 500 exposure — broad market participation"},
    {"symbol": "QQQ", "side": "BUY", "rationale": "Nasdaq-100 growth exposure — tech sector allocation"},
    {"symbol": "IWM", "side": "BUY", "rationale": "Russell 2000 small-cap diversification"},
    {"symbol": "TLT", "side": "BUY", "rationale": "Long-duration Treasury hedge against equity drawdown"},
    {"symbol": "GLD", "side": "BUY", "rationale": "Gold allocation — inflation hedge and portfolio diversifier"},
    {"symbol": "VTI", "side": "BUY", "rationale": "Total US market — low-cost broad equity core"},
    {"symbol": "BND", "side": "BUY", "rationale": "Aggregate bond exposure — fixed-income ballast"},
    {"symbol": "VXUS", "side": "BUY", "rationale": "Total international ex-US — geographic diversification"},
    {"symbol": "XLF", "side": "BUY", "rationale": "Financial sector tactical allocation"},
    {"symbol": "XLE", "side": "BUY", "rationale": "Energy sector — inflation-sensitive commodity exposure"},
]


def _run_level1_human_review_package_drill(
    demo_candidates: int = 2,
) -> dict:
    """Run Level 1 human review package drill (Phase 16H).

    Read-only drill that extends 16G by creating a review-only human review
    package/checklist artifact. Proves Werner/operator can prepare complete
    review packages for Chris without enabling orders, opening an order
    window, using H1, or calling any order endpoint.
    """
    import hashlib
    import json as _json
    import subprocess as _sp
    import urllib.request
    import urllib.error
    from datetime import datetime, timezone
    from typing import Any

    now_utc = datetime.now(timezone.utc)
    ts_str = now_utc.strftime("%Y-%m-%dT%H:%M:%SZ")
    ts_file = now_utc.strftime("%Y%m%dT%H%M%SZ")
    drill_id = f"review-package-drill-{ts_file}"
    effective_candidates = max(0, min(demo_candidates, 5))

    # ------------------------------------------------------------------
    # 1. Git / worktree
    # ------------------------------------------------------------------
    git = _git_metadata(BRIDGE_DIR)
    full_commit = git.get("commit_short", "?")
    try:
        p = _sp.run(
            ["git", "-C", str(BRIDGE_DIR), "rev-parse", "HEAD"],
            capture_output=True, text=True, timeout=5,
        )
        if p.stdout.strip():
            full_commit = p.stdout.strip()
    except Exception:
        pass

    worktree = _get_worktree_state(BRIDGE_DIR)
    origin_alignment = _get_origin_master_alignment(BRIDGE_DIR)

    git_section = {
        "branch": git.get("branch", "?"),
        "commit": full_commit if len(full_commit) > 16 else git.get("commit_short", "?"),
        "commit_short": git.get("commit_short", "?"),
        "tag": git.get("tag", "?"),
        "origin_master_commit": origin_alignment.get("origin_master_commit", "?"),
        "origin_master_aligned": origin_alignment.get("aligned"),
        "worktree_clean": worktree.get("clean"),
        "dirty_files": worktree.get("dirty_files", []),
    }

    # ------------------------------------------------------------------
    # 2. Required tags
    # ------------------------------------------------------------------
    required_tags_present: list[str] = []
    required_tags_missing: list[str] = []
    try:
        p = _sp.run(
            ["git", "-C", str(BRIDGE_DIR), "tag"],
            capture_output=True, text=True, timeout=10,
        )
        all_tags = set(p.stdout.strip().splitlines())
        for tag in _PHASE16H_REQUIRED_TAGS:
            if tag in all_tags:
                required_tags_present.append(tag)
            else:
                required_tags_missing.append(tag)
    except Exception:
        required_tags_missing = list(_PHASE16H_REQUIRED_TAGS)
        required_tags_present = []

    required_tags = {
        "required_count": len(_PHASE16H_REQUIRED_TAGS),
        "present_count": len(required_tags_present),
        "missing": required_tags_missing,
        "present": required_tags_present,
    }

    # Early exit: missing tags
    if len(required_tags_missing) > 0:
        return _phase16h_no_go(
            drill_id, ts_str, git_section, required_tags,
            _PHASE16H_DIAGNOSIS["missing_required_tags"],
            [f"Missing tags: {', '.join(required_tags_missing)}"],
        )

    # Early exit: dirty worktree
    if not git_section.get("worktree_clean", False) and git_section.get("worktree_clean") is not None:
        return _phase16h_no_go(
            drill_id, ts_str, git_section, required_tags,
            _PHASE16H_DIAGNOSIS["dirty_worktree"],
            ["Commit or stash dirty files"] + [f"  {f}" for f in git_section.get("dirty_files", [])[:5]],
        )

    # ------------------------------------------------------------------
    # 3. Bridge runtime
    # ------------------------------------------------------------------
    br_reachable = False
    br_connected = False
    br_mode = "?"
    br_read_only = False
    ep_ok = 0
    ep_display = "?"
    try:
        req = urllib.request.Request(f"{BRIDGE_URL}/health", method="GET")
        with urllib.request.urlopen(req, timeout=8) as resp:
            if resp.status == 200:
                br_reachable = True
                hd = _json.loads(resp.read().decode())
                br_connected = hd.get("connected", False)
                br_mode = hd.get("mode", "?")
                br_read_only = br_mode == "paper"
    except Exception:
        pass

    snapshot_used = False
    if br_reachable:
        try:
            req = urllib.request.Request(f"{BRIDGE_URL}/snapshot", method="GET")
            with urllib.request.urlopen(req, timeout=8) as resp:
                if resp.status == 200:
                    snapshot_used = True
                    ep_ok = 7
                    ep_display = f"{ep_ok}/7 OK (snapshot)"
        except Exception:
            pass

    if not snapshot_used and br_reachable:
        _EPS = ["/health", "/readiness", "/status", "/monitor/reconciliation",
                "/monitor/alerts", "/monitor/events", "/positions", "/account"]
        for ep in _EPS:
            try:
                req = urllib.request.Request(f"{BRIDGE_URL}{ep}", method="GET")
                with urllib.request.urlopen(req, timeout=5) as resp:
                    if resp.status == 200:
                        ep_ok += 1
            except Exception:
                pass
        ep_display = f"{ep_ok}/{len(_EPS)} OK"

    positions_count = 0
    positions_flat = True
    if br_reachable:
        try:
            req = urllib.request.Request(f"{BRIDGE_URL}/positions", method="GET")
            with urllib.request.urlopen(req, timeout=8) as resp:
                if resp.status == 200:
                    pd = _json.loads(resp.read().decode())
                    pl = pd.get("positions", [])
                    positions_count = len(pl)
                    positions_flat = all(abs(p.get("position", 0)) < 0.01 for p in pl)
        except Exception:
            pass

    active_alerts_count = 0
    if br_reachable:
        try:
            req = urllib.request.Request(f"{BRIDGE_URL}/monitor/alerts", method="GET")
            with urllib.request.urlopen(req, timeout=8) as resp:
                if resp.status == 200:
                    ad = _json.loads(resp.read().decode())
                    all_a = ad.get("alerts", [])
                    active_alerts_count = sum(1 for a in all_a if isinstance(a, dict) and a.get("requires_action", False))
        except Exception:
            pass

    runtime_section = {
        "bridge_reachable": br_reachable,
        "bridge_connected": br_connected,
        "mode": br_mode,
        "read_only": br_read_only,
        "endpoints_display": ep_display,
        "endpoints_ok": ep_ok,
        "positions_count": positions_count,
        "positions_flat": positions_flat,
        "active_alerts_count": active_alerts_count,
    }

    # ------------------------------------------------------------------
    # 4. Safety flags
    # ------------------------------------------------------------------
    env_safety = _read_env_safety(BRIDGE_DIR / ".env")
    rules_state = _read_rules_enforced(
        Path.home() / ".openclaw" / "risk-rules" / "paper-trading-rules.yaml"
    )
    autonomy_path = BRIDGE_DIR / "docs" / "AUTONOMY_CRITERIA.md"
    autonomy_level = _read_autonomy_level(autonomy_path)

    env_allow_orders = env_safety.get("IBKR_ALLOW_ORDERS", "?")
    rules_enforced = rules_state.get("enforced", "?")
    system_locked = True
    if br_reachable:
        try:
            req = urllib.request.Request(f"{BRIDGE_URL}/readiness", method="GET")
            with urllib.request.urlopen(req, timeout=5) as resp:
                if resp.status == 200:
                    rd = _json.loads(resp.read().decode())
                    system_locked = rd.get("summary", {}).get("kill_switches", {}).get("system_locked", True)
        except Exception:
            pass

    safety_section = {
        "env_IBKR_ALLOW_ORDERS": env_allow_orders,
        "rules_enforced": rules_enforced,
        "system_locked": system_locked,
    }

    # ------------------------------------------------------------------
    # 5. Guard state — centralized assessor
    # ------------------------------------------------------------------
    gs_assessment = _assess_guard_state_cleanliness(now_utc)
    guard_section = gs_assessment["guard_section"]

    # ------------------------------------------------------------------
    # 6. Doctor / KPI / Policy
    # ------------------------------------------------------------------
    doctor_section: dict = {}
    try:
        dr = run_doctor()
        doc_pass = dr.get("passed", 0)
        doc_total = dr.get("total", 0)
        doctor_ok = dr.get("pass", False)
        doc_h1_status = "?"
        for c in dr.get("checks", []):
            if c.get("check") == "h1_token_canary":
                if c.get("status") == "MANUAL_REQUIRED":
                    doc_h1_status = "MANUAL_REQUIRED"
                elif c.get("ok"):
                    doc_h1_status = "PASS"
                else:
                    doc_h1_status = "FAIL"
                break
        doc_acceptable = doctor_ok or (
            doc_h1_status == "MANUAL_REQUIRED" and doc_pass >= doc_total - 1
        )
        doctor_section = {
            "result": "PASS" if doctor_ok else ("PASS_WITH_H1_MANUAL" if doc_acceptable else "FAIL"),
            "h1_canary_status": doc_h1_status,
            "acceptable": doc_acceptable,
        }
    except Exception as e:
        doctor_section = {"result": "ERROR", "h1_canary_status": "ERROR", "acceptable": False, "error": str(e)[:200]}

    kpi_section: dict = {}
    kpi_clean_cycles: int | None = None
    try:
        kpi_result = run_kpi()
        kpi_verdict = kpi_result.get("verdict", "ERROR")
        kpi_blockers = kpi_result.get("blockers", [])
        no_go_blockers = [b for b in kpi_blockers if b.get("severity") == "NO-GO"]
        kpi_acceptable_hold = (
            kpi_verdict == "HOLD" and len(no_go_blockers) == 0
            and any(b.get("check") == "system_locked"
                    for b in kpi_blockers if b.get("severity") == "HOLD")
        )
        au = kpi_result.get("autonomy", {})
        if isinstance(au, dict):
            kpi_clean_cycles = au.get("clean_cycles")
            if kpi_clean_cycles is None:
                kpi_clean_cycles = kpi_result.get("clean_cycles")
        if kpi_clean_cycles is None:
            kpi_clean_cycles = kpi_result.get("clean_cycles")
        kpi_section = {
            "verdict": kpi_verdict,
            "blockers": [b.get("check", "?") for b in kpi_blockers],
            "acceptable_hold": kpi_acceptable_hold,
        }
    except Exception as e:
        kpi_section = {"verdict": "ERROR", "blockers": [], "acceptable_hold": False, "error": str(e)[:200]}

    policy_result = _check_hermes_policy()
    policy_section = {
        "hermes_policy_exists": policy_result["hermes_policy_exists"],
        "advisory_boundary_ok": policy_result["advisory_boundary_ok"],
        "execution_path_ok": policy_result["execution_path_ok"],
    }

    # ------------------------------------------------------------------
    # 7. Clean-cycles — canonical source
    # ------------------------------------------------------------------
    canonical_ledger_path = OPENCLAW_DIR / "autonomy-cycles" / "clean-cycle-ledger.jsonl"
    clean_cycles_source = "openclaw_clean_cycle_ledger"
    drill_clean_cycles: int | None = None
    try:
        if canonical_ledger_path.exists():
            drill_clean_cycles = _count_clean_cycles(OPENCLAW_DIR)
    except Exception:
        drill_clean_cycles = None

    clean_cycles_matches_kpi = False
    if kpi_clean_cycles is not None and drill_clean_cycles is not None:
        clean_cycles_matches_kpi = (kpi_clean_cycles == drill_clean_cycles)
    elif kpi_clean_cycles is None and drill_clean_cycles is None:
        clean_cycles_matches_kpi = True

    autonomy_section = {
        "current_level": autonomy_level,
        "clean_cycles": drill_clean_cycles,
        "clean_cycles_source": clean_cycles_source,
        "clean_cycles_matches_kpi": clean_cycles_matches_kpi,
    }

    # ------------------------------------------------------------------
    # 8. Generate review package items (read-only synthetic)
    # ------------------------------------------------------------------
    items_created = 0
    review_items: list[dict[str, Any]] = []
    has_executable = False

    for i in range(min(effective_candidates, len(_REVIEW_CANDIDATE_POOL))):
        candidate = _REVIEW_CANDIDATE_POOL[i]
        rid = f"review-item-{drill_id}-{i+1:03d}"
        quantity = (i + 1) * 10
        item: dict[str, Any] = {
            "review_id": rid,
            "source": "synthetic_readonly_demo",
            "symbol": candidate["symbol"],
            "side": candidate["side"],
            "quantity": quantity,
            "rationale": candidate["rationale"],
            "risk_notes": (
                f"Synthetic demo review item — not executable. "
                f"Max position size: {quantity} shares. "
                f"Requires Chris review and explicit approval before any order path."
            ),
            "executable": False,
            "requires_chris_approval": True,
            "future_required_path": "/order/preflight -> /order/approve -> /order/submit",
            "performed": False,
            "review_status": "pending_review",
            "review_checklist": [
                {"step": "verify_safety_locks", "description": "Confirm all safety locks engaged", "passed": True},
                {"step": "verify_guard_clean", "description": "Confirm guard-state is clean", "passed": True},
                {"step": "verify_position_sizing", "description": f"Confirm {quantity} shares within risk limits", "passed": None},
                {"step": "verify_market_conditions", "description": "Check market conditions before execution", "passed": None},
                {"step": "chris_approval", "description": "Chris explicitly approves this item", "passed": False},
                {"step": "h1_token_available", "description": "H1 token is available for future submit", "passed": None},
            ],
        }
        review_items.append(item)
        items_created += 1

    review_package_id = f"review-package-{ts_file}"
    review_package = {
        "package_id": review_package_id,
        "status": "review_only",
        "generated_by": "level1-human-review-package-drill (Phase 16H)",
        "requires_human_review": True,
        "review_deadline_hint": "Before any order enablement",
        "items": review_items,
        "summary": {
            "total_items": items_created,
            "executable_items": 0,
            "pending_review_items": items_created,
            "approved_items": 0,
            "rejected_items": 0,
        },
    }

    review_workflow = {
        "review_only": True,
        "demo_candidates_requested": effective_candidates,
        "candidates_examined": effective_candidates,
        "items_created": items_created,
        "items_marked_executable": False,
        "all_items_require_chris_review": True,
        "human_approval_required": True,
        "h1_required_for_future_submit": True,
        "order_window_required_for_future_submit": True,
        "order_routing_disallowed": True,
        "broker_submission_performed": False,
        "preflight_performed": False,
        "approval_performed": False,
        "submit_performed": False,
    }

    workflow_summary = {
        "level1_human_review_package_ready": True,
        "review_package_created": items_created > 0,
        "all_items_non_executable": all(not it.get("executable", True) for it in review_items),
        "all_items_require_human_approval": all(it.get("requires_chris_approval", True) for it in review_items),
        "no_order_path_called": True,
        "no_broker_submission": True,
        "no_h1_seen": True,
        "no_order_window_seen": True,
    }

    # ------------------------------------------------------------------
    # 9. Classification
    # ------------------------------------------------------------------
    all_tags_present = len(required_tags_missing) == 0
    worktree_clean = git_section.get("worktree_clean", False)
    run_time_ready = br_connected and br_mode == "paper" and br_read_only
    safety_locked = env_allow_orders in ("false", "?") and rules_enforced in ("false", "?") and system_locked is True

    if not all_tags_present:
        diagnosis = _PHASE16H_DIAGNOSIS["missing_required_tags"]
        severity = "NO_GO"
    elif not worktree_clean and worktree_clean is not None:
        diagnosis = _PHASE16H_DIAGNOSIS["dirty_worktree"]
        severity = "NO_GO"
    elif not positions_flat and positions_count > 0:
        diagnosis = _PHASE16H_DIAGNOSIS["positions_not_flat"]
        severity = "NO_GO"
    elif active_alerts_count > 0:
        diagnosis = _PHASE16H_DIAGNOSIS["monitor_alerts_active"]
        severity = "NO_GO"
    elif not run_time_ready:
        diagnosis = _PHASE16H_DIAGNOSIS["runtime_not_ready"]
        severity = "HOLD" if not br_connected else "NO_GO"
    elif not safety_locked:
        diagnosis = _PHASE16H_DIAGNOSIS["safety_not_locked"]
        severity = "NO_GO"
    elif autonomy_level != "1":
        diagnosis = _PHASE16H_DIAGNOSIS["autonomy_not_level1"]
        severity = "NO_GO"
    elif not gs_assessment["guard_state_clean"]:
        diagnosis = _PHASE16H_DIAGNOSIS["guard_state_not_clean"]
        severity = "NO_GO"
    elif not doc_acceptable:
        diagnosis = _PHASE16H_DIAGNOSIS["doctor_not_acceptable"]
        severity = "NO_GO"
    elif not kpi_acceptable_hold:
        diagnosis = _PHASE16H_DIAGNOSIS["kpi_not_acceptable"]
        severity = "NO_GO"
    elif not policy_result["hermes_policy_exists"] or not policy_result["execution_path_ok"]:
        diagnosis = _PHASE16H_DIAGNOSIS["policy_boundary_missing"]
        severity = "NO_GO"
    elif not clean_cycles_matches_kpi:
        diagnosis = _PHASE16H_DIAGNOSIS["clean_cycles_mismatch"]
        severity = "NO_GO"
    elif has_executable:
        diagnosis = _PHASE16H_DIAGNOSIS["executable_item_present"]
        severity = "NO_GO"
    else:
        diagnosis = _PHASE16H_DIAGNOSIS["ready"]
        severity = "OK"

    drill_ok = diagnosis == _PHASE16H_DIAGNOSIS["ready"]
    operator_action_required = not drill_ok
    suggested_actions: list[str] = []
    if not drill_ok:
        suggested_actions.append(f"Review package drill blocked: {diagnosis}")
        if not run_time_ready:
            suggested_actions.append("Ensure bridge is connected in paper read-only mode")
        if not safety_locked:
            suggested_actions.append("Verify all safety locks are engaged")
        if not gs_assessment["guard_state_clean"]:
            suggested_actions.append("Run guard-state-reconcile to fix guard state")

    # ------------------------------------------------------------------
    # 10. Evidence hash
    # ------------------------------------------------------------------
    hashable = {
        "diagnosis": diagnosis, "severity": severity,
        "items_created": items_created,
        "all_non_executable": not has_executable,
        "no_broker_mutation": True,
        "no_order_window_opened": True,
    }
    evidence_hash = _compute_evidence_hash(hashable)

    # ------------------------------------------------------------------
    # 11. Assemble result
    # ------------------------------------------------------------------
    result: dict[str, Any] = {
        "command": "ibkr-operator level1-human-review-package-drill",
        "advisory": (
            "Read-only Level 1 human review package drill (Phase 16H). "
            "Extends 16G by creating a review-only human review package/checklist artifact. "
            "No orders. No mutations. No H1 token. No broker activity. "
            "No autonomy level change. All items are non-executable and require Chris approval."
        ),
        "timestamp": ts_str,
        "drill_id": drill_id,
        "diagnosis": diagnosis,
        "severity": severity,
        "operator_action_required": operator_action_required,
        "suggested_operator_actions": suggested_actions,
        "git": git_section,
        "required_tags": required_tags,
        "runtime": runtime_section,
        "autonomy": autonomy_section,
        "safety": safety_section,
        "guard_state": guard_section,
        "review_workflow": review_workflow,
        "review_package": review_package,
        "workflow_summary": workflow_summary,
        "kpi_summary": kpi_section,
        "doctor_summary": doctor_section,
        "policy_summary": policy_section,
        "promotion_allowed_now": False,
        "order_enablement_allowed_now": False,
        "order_enablement_performed": False,
        "promotion_performed": False,
        "no_broker_mutation": True,
        "no_order_window_opened": True,
        "no_order_window_seen": True,
        "no_h1_seen": True,
        "h1_token_not_used": True,
        "evidence_hash": evidence_hash,
        "explicit_non_actions": _PHASE16H_EXPLICIT_NON_ACTIONS,
    }

    # ------------------------------------------------------------------
    # 12. Export artifacts (JSON + review package artifact)
    # ------------------------------------------------------------------
    export_path: str | None = None
    review_package_path: str | None = None
    try:
        _PHASE16H_EXPORT_DIR.mkdir(parents=True, exist_ok=True)
        # Main JSON export
        ep = _PHASE16H_EXPORT_DIR / f"{drill_id}.json"
        with open(ep, "w", encoding="utf-8") as f:
            _json.dump(result, f, indent=2, default=str)
        export_path = str(ep)
        # Review package artifact (standalone)
        rp_path = _PHASE16H_EXPORT_DIR / f"{review_package_id}.json"
        with open(rp_path, "w", encoding="utf-8") as f:
            _json.dump(review_package, f, indent=2, default=str)
        review_package_path = str(rp_path)
    except Exception:
        pass

    result["export_path"] = export_path
    result["review_package_path"] = review_package_path
    return result


def _phase16h_no_go(
    drill_id: str, ts_str: str, git_section: dict, required_tags: dict,
    diagnosis: str, actions: list,
) -> dict:
    """Build a NO_GO result for early-exit prerequisite failures."""
    return {
        "command": "ibkr-operator level1-human-review-package-drill",
        "timestamp": ts_str,
        "drill_id": drill_id,
        "diagnosis": diagnosis,
        "severity": "NO_GO",
        "operator_action_required": True,
        "suggested_operator_actions": actions,
        "git": git_section,
        "required_tags": required_tags,
        "runtime": {},
        "autonomy": {},
        "safety": {},
        "guard_state": {},
        "review_workflow": {},
        "review_package": {"package_id": drill_id, "status": "blocked", "items": []},
        "workflow_summary": {},
        "kpi_summary": {},
        "doctor_summary": {},
        "policy_summary": {},
        "promotion_allowed_now": False,
        "order_enablement_allowed_now": False,
        "order_enablement_performed": False,
        "promotion_performed": False,
        "no_broker_mutation": True,
        "no_order_window_opened": True,
        "no_order_window_seen": True,
        "no_h1_seen": True,
        "h1_token_not_used": True,
        "evidence_hash": _compute_evidence_hash({"diagnosis": diagnosis}),
        "explicit_non_actions": _PHASE16H_EXPLICIT_NON_ACTIONS,
    }


def _print_level1_human_review_package_drill(result: dict) -> None:
    """Print Phase 16H human review package drill in human-readable format."""
    drill_ok = result.get("diagnosis") == _PHASE16H_DIAGNOSIS["ready"]
    diag_color = GREEN if drill_ok else RED
    sev = result.get("severity", "?")
    sev_color = GREEN if sev == "OK" else (YELLOW if sev == "HOLD" else RED)

    print(f"{BOLD}══════════════════════════════════════════════════{RESET}")
    print(f"{BOLD}  Level 1 Human Review Package Drill (16H){RESET}")
    print(f"{BOLD}══════════════════════════════════════════════════{RESET}\n")
    print(f"  Drill ID:        {result.get('drill_id', '?')}")
    print(f"  Timestamp:       {result.get('timestamp', '?')}")
    print(f"  Diagnosis:       {diag_color}{result.get('diagnosis', '?')}{RESET}")
    print(f"  Severity:        {sev_color}{sev}{RESET}")
    print()

    rw = result.get("review_workflow", {})
    if rw:
        print(f"  {BOLD}Review Workflow{RESET}")
        print(f"    Review-only:            {rw.get('review_only')}")
        print(f"    Candidates requested:   {rw.get('demo_candidates_requested', 0)}")
        print(f"    Items created:          {rw.get('items_created', 0)}")
        print(f"    Marked executable:      {RED}{rw.get('items_marked_executable')}{RESET}")
        print(f"    Requires Chris review:  {GREEN}{rw.get('all_items_require_chris_review')}{RESET}")
        print(f"    Broker submission:      {RED}{rw.get('broker_submission_performed')}{RESET}")
        print()

    wf = result.get("workflow_summary", {})
    if wf:
        print(f"  {BOLD}Workflow Summary{RESET}")
        for key, val in wf.items():
            color = GREEN if val else RED
            print(f"    {key:<42} {color}{val}{RESET}")
        print()

    rp = result.get("review_package", {})
    if rp:
        print(f"  {BOLD}Review Package{RESET}")
        print(f"    Package ID:    {rp.get('package_id', '?')}")
        print(f"    Status:        {rp.get('status', '?')}")
        items = rp.get("items", [])
        print(f"    Items:         {len(items)}")
        for item in items:
            side_color = GREEN if item.get('side') == 'BUY' else RED
            print(f"      {item.get('review_id', '?')}: {item.get('symbol', '?')} "
                  f"{side_color}{item.get('side', '?')}{RESET} "
                  f"qty={item.get('quantity', 0)} "
                  f"status={item.get('review_status', '?')} "
                  f"exec={RED}{item.get('executable')}{RESET}")
        summary = rp.get("summary", {})
        if summary:
            print(f"    Summary:       total={summary.get('total_items', 0)} "
                  f"exec={summary.get('executable_items', 0)} "
                  f"pending={summary.get('pending_review_items', 0)}")
        print()

    auto = result.get("autonomy", {})
    if auto:
        print(f"  {BOLD}Autonomy{RESET}")
        print(f"    Level:          {auto.get('current_level', '?')}")
        cc = auto.get('clean_cycles')
        print(f"    Clean cycles:   {cc if cc is not None else 'null'}")
        print(f"    Matches KPI:    {auto.get('clean_cycles_matches_kpi')}")
        print()

    safety = result.get("safety", {})
    if safety:
        print(f"  {BOLD}Safety{RESET}")
        print(f"    ALLOW_ORDERS:   {safety.get('env_IBKR_ALLOW_ORDERS', '?')}")
        print(f"    rules.enforced: {safety.get('rules_enforced', '?')}")
        print(f"    system_locked:  {_bool_str(safety.get('system_locked'))}")
        print()

    runtime = result.get("runtime", {})
    if runtime:
        print(f"  {BOLD}Runtime{RESET}")
        print(f"    Bridge:         connected={_bool_str(runtime.get('bridge_connected'))} mode={runtime.get('mode', '?')}")
        print(f"    Endpoints:      {runtime.get('endpoints_display', '?')}")
        print(f"    Positions:      {runtime.get('positions_count', 0)}  flat={_bool_str(runtime.get('positions_flat'))}")
        print(f"    Alerts:         {runtime.get('active_alerts_count', 0)}")
        print()

    guard = result.get("guard_state", {})
    if guard:
        print(f"  {BOLD}Guard State{RESET}")
        print(f"    Trade count:    {guard.get('daily_trade_count', '?')}")
        print(f"    Trade date:     {guard.get('trade_date', '?')}")
        print(f"    Stale:          {_bool_str(guard.get('trade_date_stale'))}")
        print(f"    Clean:          {_bool_str(guard.get('guard_state_clean'))}")
        print()

    sa = result.get("suggested_operator_actions", [])
    if sa:
        print(f"  {BOLD}Suggested Actions{RESET}")
        for a in sa:
            print(f"    {YELLOW}→{RESET} {a}")
        print()

    print(f"  {BOLD}Advisory{RESET}")
    print(f"    {result.get('advisory', '')}")

    eh = result.get("evidence_hash", "")
    if eh:
        print(f"\n  Evidence hash: {eh[:16]}...")

    ep = result.get("export_path") or result.get("_export_path")
    if ep:
        print(f"  Export: {ep}")
    rp_path = result.get("review_package_path")
    if rp_path:
        print(f"  Review package: {rp_path}")
    print()


# ===========================================================================
# Phase 16I — Level 1 Review Decision Drill
# ===========================================================================

_PHASE16I_EXPORT_DIR = OPENCLAW_DIR / "level1-review-decisions"

_PHASE16I_REQUIRED_TAGS: tuple[str, ...] = (
    "phase16h_level1_human_review_package_drill",
    "phase16g_level1_proposal_workflow_drill",
    "phase16f_level1_evidence_normalization",
)

_PHASE16I_DIAGNOSIS = {
    "ready": "level1_review_decision_ok",
    "missing_required_tags": "missing_required_tags",
    "dirty_worktree": "dirty_worktree",
    "autonomy_not_level1": "autonomy_not_level1",
    "runtime_not_ready": "runtime_not_ready",
    "safety_not_locked": "safety_not_locked",
    "guard_state_not_clean": "guard_state_not_clean",
    "positions_not_flat": "positions_not_flat",
    "monitor_alerts_active": "monitor_alerts_active",
    "doctor_not_acceptable": "doctor_not_acceptable",
    "kpi_not_acceptable": "kpi_not_acceptable",
    "policy_boundary_missing": "policy_boundary_missing",
    "clean_cycles_mismatch": "clean_cycles_mismatch",
    "review_package_not_found": "review_package_not_found",
    "review_package_not_review_only": "review_package_not_review_only",
    "unknown": "unknown",
}

_PHASE16I_EXPLICIT_NON_ACTIONS: list[str] = [
    "This command did not change autonomy level.",
    "This command did not enable orders.",
    "This command did not change IBKR_ALLOW_ORDERS.",
    "This command did not change rules.enforced.",
    "This command did not unlock system_locked.",
    "This command did not open an order window.",
    "This command did not read H1 token.",
    "This command did not call trade-window helper.",
    "This command did not call /order, /order/preflight, /order/approve, or /order/submit.",
    "This command did not submit orders.",
    "This command did not call broker mutation endpoints.",
    "This command did not restart bridge.",
    "This command did not reconnect automatically.",
    "This command did not repair guard-state.",
    "Only allowed writes are the export artifact and decision artifact.",
    "Accepted items are advisory/audit only — they do NOT trigger order paths.",
]

_DECISION_MODE_VALUES = ("mixed_demo", "accept_all_demo", "reject_all_demo", "defer_all_demo")

# Decision engine: per-mode logic for each review item
_DECISION_LOGIC = {
    "accept_all_demo": lambda i, item: "accept",
    "reject_all_demo": lambda i, item: "reject",
    "defer_all_demo": lambda i, item: "defer",
    "mixed_demo": lambda i, item: "accept" if i % 2 == 0 else ("reject" if i % 3 == 1 else "defer"),
}

_DECISION_RATIONALE_TEMPLATES = {
    "accept": "Advisory acceptance — signals readiness for future order consideration. Does NOT enable orders, open trade window, or route to broker.",
    "reject": "Rejected — rationale may include insufficient risk assessment, market conditions, or position-sizing concerns. Item will not proceed.",
    "defer": "Deferred — requires additional review, data, or conditions before acceptance. Item remains in pending state.",
}


def _run_level1_review_decision_drill(
    demo_candidates: int = 2,
    decision_mode: str = "mixed_demo",
    review_package_path: str | None = None,
) -> dict:
    """Run Level 1 review decision drill (Phase 16I).

    Read-only drill that applies accept/reject/defer decisions to a review
    package and produces an advisory audit decision artifact. Accepted items
    remain non-executable; no order paths are triggered.
    """
    import hashlib
    import json as _json
    import subprocess as _sp
    import urllib.request
    import urllib.error
    from datetime import datetime, timezone
    from typing import Any

    now_utc = datetime.now(timezone.utc)
    ts_str = now_utc.strftime("%Y-%m-%dT%H:%M:%SZ")
    ts_file = now_utc.strftime("%Y%m%dT%H%M%SZ")
    drill_id = f"review-decision-drill-{ts_file}"
    effective_candidates = max(0, min(demo_candidates, 5))
    if decision_mode not in _DECISION_MODE_VALUES:
        decision_mode = "mixed_demo"

    # ------------------------------------------------------------------
    # 1. Git / worktree
    # ------------------------------------------------------------------
    git_cfg = _git_metadata(BRIDGE_DIR)
    full_commit = git_cfg.get("commit_short", "?")
    try:
        p = _sp.run(
            ["git", "-C", str(BRIDGE_DIR), "rev-parse", "HEAD"],
            capture_output=True, text=True, timeout=5,
        )
        if p.stdout.strip():
            full_commit = p.stdout.strip()
    except Exception:
        pass

    worktree = _get_worktree_state(BRIDGE_DIR)
    origin_alignment = _get_origin_master_alignment(BRIDGE_DIR)

    git_section = {
        "branch": git_cfg.get("branch", "?"),
        "commit": full_commit if len(full_commit) > 16 else git_cfg.get("commit_short", "?"),
        "commit_short": git_cfg.get("commit_short", "?"),
        "tag": git_cfg.get("tag", "?"),
        "origin_master_commit": origin_alignment.get("origin_master_commit", "?"),
        "origin_master_aligned": origin_alignment.get("aligned"),
        "worktree_clean": worktree.get("clean"),
        "dirty_files": worktree.get("dirty_files", []),
    }

    # ------------------------------------------------------------------
    # 2. Required tags
    # ------------------------------------------------------------------
    required_tags_present: list[str] = []
    required_tags_missing: list[str] = []
    try:
        p = _sp.run(
            ["git", "-C", str(BRIDGE_DIR), "tag"],
            capture_output=True, text=True, timeout=10,
        )
        all_tags = set(p.stdout.strip().splitlines())
        for tag in _PHASE16I_REQUIRED_TAGS:
            if tag in all_tags:
                required_tags_present.append(tag)
            else:
                required_tags_missing.append(tag)
    except Exception:
        required_tags_missing = list(_PHASE16I_REQUIRED_TAGS)
        required_tags_present = []

    required_tags = {
        "required_count": len(_PHASE16I_REQUIRED_TAGS),
        "present_count": len(required_tags_present),
        "missing": required_tags_missing,
        "present": required_tags_present,
    }

    if len(required_tags_missing) > 0:
        return _phase16i_no_go(
            drill_id, ts_str, git_section, required_tags,
            _PHASE16I_DIAGNOSIS["missing_required_tags"],
            [f"Missing tags: {', '.join(required_tags_missing)}"],
        )

    if not git_section.get("worktree_clean", False) and git_section.get("worktree_clean") is not None:
        return _phase16i_no_go(
            drill_id, ts_str, git_section, required_tags,
            _PHASE16I_DIAGNOSIS["dirty_worktree"],
            ["Commit or stash dirty files"] + [f"  {f}" for f in git_section.get("dirty_files", [])[:5]],
        )

    # ------------------------------------------------------------------
    # 3. Bridge runtime
    # ------------------------------------------------------------------
    br_reachable = False
    br_connected = False
    br_mode = "?"
    br_read_only = False
    ep_ok = 0
    ep_display = "?"
    try:
        req = urllib.request.Request(f"{BRIDGE_URL}/health", method="GET")
        with urllib.request.urlopen(req, timeout=8) as resp:
            if resp.status == 200:
                br_reachable = True
                hd = _json.loads(resp.read().decode())
                br_connected = hd.get("connected", False)
                br_mode = hd.get("mode", "?")
                br_read_only = br_mode == "paper"
    except Exception:
        pass

    snapshot_used = False
    if br_reachable:
        try:
            req = urllib.request.Request(f"{BRIDGE_URL}/snapshot", method="GET")
            with urllib.request.urlopen(req, timeout=8) as resp:
                if resp.status == 200:
                    snapshot_used = True
                    ep_ok = 7
                    ep_display = f"{ep_ok}/7 OK (snapshot)"
        except Exception:
            pass

    if not snapshot_used and br_reachable:
        _EPS = ["/health", "/readiness", "/status", "/monitor/reconciliation",
                "/monitor/alerts", "/monitor/events", "/positions", "/account"]
        for ep in _EPS:
            try:
                req = urllib.request.Request(f"{BRIDGE_URL}{ep}", method="GET")
                with urllib.request.urlopen(req, timeout=5) as resp:
                    if resp.status == 200:
                        ep_ok += 1
            except Exception:
                pass
        ep_display = f"{ep_ok}/{len(_EPS)} OK"

    positions_count = 0
    positions_flat = True
    if br_reachable:
        try:
            req = urllib.request.Request(f"{BRIDGE_URL}/positions", method="GET")
            with urllib.request.urlopen(req, timeout=8) as resp:
                if resp.status == 200:
                    pd = _json.loads(resp.read().decode())
                    pl = pd.get("positions", [])
                    positions_count = len(pl)
                    positions_flat = all(abs(p.get("position", 0)) < 0.01 for p in pl)
        except Exception:
            pass

    active_alerts_count = 0
    if br_reachable:
        try:
            req = urllib.request.Request(f"{BRIDGE_URL}/monitor/alerts", method="GET")
            with urllib.request.urlopen(req, timeout=8) as resp:
                if resp.status == 200:
                    ad = _json.loads(resp.read().decode())
                    all_a = ad.get("alerts", [])
                    active_alerts_count = sum(1 for a in all_a if isinstance(a, dict) and a.get("requires_action", False))
        except Exception:
            pass

    runtime_section = {
        "bridge_reachable": br_reachable,
        "bridge_connected": br_connected,
        "mode": br_mode,
        "read_only": br_read_only,
        "endpoints_display": ep_display,
        "endpoints_ok": ep_ok,
        "positions_count": positions_count,
        "positions_flat": positions_flat,
        "active_alerts_count": active_alerts_count,
    }

    # ------------------------------------------------------------------
    # 4. Safety flags
    # ------------------------------------------------------------------
    env_safety = _read_env_safety(BRIDGE_DIR / ".env")
    rules_state = _read_rules_enforced(
        Path.home() / ".openclaw" / "risk-rules" / "paper-trading-rules.yaml"
    )
    autonomy_path = BRIDGE_DIR / "docs" / "AUTONOMY_CRITERIA.md"
    autonomy_level = _read_autonomy_level(autonomy_path)

    env_allow_orders = env_safety.get("IBKR_ALLOW_ORDERS", "?")
    rules_enforced = rules_state.get("enforced", "?")
    system_locked = True
    if br_reachable:
        try:
            req = urllib.request.Request(f"{BRIDGE_URL}/readiness", method="GET")
            with urllib.request.urlopen(req, timeout=5) as resp:
                if resp.status == 200:
                    rd = _json.loads(resp.read().decode())
                    system_locked = rd.get("summary", {}).get("kill_switches", {}).get("system_locked", True)
        except Exception:
            pass

    safety_section = {
        "env_IBKR_ALLOW_ORDERS": env_allow_orders,
        "rules_enforced": rules_enforced,
        "system_locked": system_locked,
    }

    # ------------------------------------------------------------------
    # 5. Guard state — centralized assessor
    # ------------------------------------------------------------------
    gs_assessment = _assess_guard_state_cleanliness(now_utc)
    guard_section = gs_assessment["guard_section"]

    # ------------------------------------------------------------------
    # 6. Doctor / KPI / Policy
    # ------------------------------------------------------------------
    doctor_section: dict = {}
    try:
        dr = run_doctor()
        doc_pass = dr.get("passed", 0)
        doc_total = dr.get("total", 0)
        doctor_ok = dr.get("pass", False)
        doc_h1_status = "?"
        for c in dr.get("checks", []):
            if c.get("check") == "h1_token_canary":
                if c.get("status") == "MANUAL_REQUIRED":
                    doc_h1_status = "MANUAL_REQUIRED"
                elif c.get("ok"):
                    doc_h1_status = "PASS"
                else:
                    doc_h1_status = "FAIL"
                break
        doc_acceptable = doctor_ok or (
            doc_h1_status == "MANUAL_REQUIRED" and doc_pass >= doc_total - 1
        )
        doctor_section = {
            "result": "PASS" if doctor_ok else ("PASS_WITH_H1_MANUAL" if doc_acceptable else "FAIL"),
            "h1_canary_status": doc_h1_status,
            "acceptable": doc_acceptable,
        }
    except Exception as e:
        doctor_section = {"result": "ERROR", "h1_canary_status": "ERROR", "acceptable": False, "error": str(e)[:200]}

    kpi_section: dict = {}
    kpi_clean_cycles: int | None = None
    try:
        kpi_result = run_kpi()
        kpi_verdict = kpi_result.get("verdict", "ERROR")
        kpi_blockers = kpi_result.get("blockers", [])
        no_go_blockers = [b for b in kpi_blockers if b.get("severity") == "NO-GO"]
        kpi_acceptable_hold = (
            kpi_verdict == "HOLD" and len(no_go_blockers) == 0
            and any(b.get("check") == "system_locked"
                    for b in kpi_blockers if b.get("severity") == "HOLD")
        )
        au = kpi_result.get("autonomy", {})
        if isinstance(au, dict):
            kpi_clean_cycles = au.get("clean_cycles")
            if kpi_clean_cycles is None:
                kpi_clean_cycles = kpi_result.get("clean_cycles")
        if kpi_clean_cycles is None:
            kpi_clean_cycles = kpi_result.get("clean_cycles")
        kpi_section = {
            "verdict": kpi_verdict,
            "blockers": [b.get("check", "?") for b in kpi_blockers],
            "acceptable_hold": kpi_acceptable_hold,
        }
    except Exception as e:
        kpi_section = {"verdict": "ERROR", "blockers": [], "acceptable_hold": False, "error": str(e)[:200]}

    policy_result = _check_hermes_policy()
    policy_section = {
        "hermes_policy_exists": policy_result["hermes_policy_exists"],
        "advisory_boundary_ok": policy_result["advisory_boundary_ok"],
        "execution_path_ok": policy_result["execution_path_ok"],
    }

    # ------------------------------------------------------------------
    # 7. Clean-cycles
    # ------------------------------------------------------------------
    canonical_ledger_path = OPENCLAW_DIR / "autonomy-cycles" / "clean-cycle-ledger.jsonl"
    clean_cycles_source = "openclaw_clean_cycle_ledger"
    drill_clean_cycles: int | None = None
    try:
        if canonical_ledger_path.exists():
            drill_clean_cycles = _count_clean_cycles(OPENCLAW_DIR)
    except Exception:
        drill_clean_cycles = None

    clean_cycles_matches_kpi = False
    if kpi_clean_cycles is not None and drill_clean_cycles is not None:
        clean_cycles_matches_kpi = (kpi_clean_cycles == drill_clean_cycles)
    elif kpi_clean_cycles is None and drill_clean_cycles is None:
        clean_cycles_matches_kpi = True

    autonomy_section = {
        "current_level": autonomy_level,
        "clean_cycles": drill_clean_cycles,
        "clean_cycles_source": clean_cycles_source,
        "clean_cycles_matches_kpi": clean_cycles_matches_kpi,
    }

    # ------------------------------------------------------------------
    # 8. Load or reject input review package
    # ------------------------------------------------------------------
    review_package_source = "synthesized_internally"
    review_package_path_actual: str | None = None
    review_items: list[dict[str, Any]] = []
    package_id = "synthetic-demo"
    package_is_review_only = True

    if review_package_path:
        rp_path_obj = Path(review_package_path)
        if not rp_path_obj.exists() or not rp_path_obj.is_file():
            return _phase16i_no_go(
                drill_id, ts_str, git_section, required_tags,
                _PHASE16I_DIAGNOSIS["review_package_not_found"],
                [f"Review package not found: {review_package_path}"],
            )
        try:
            with open(rp_path_obj) as f:
                rp_loaded = _json.load(f)
        except Exception:
            return _phase16i_no_go(
                drill_id, ts_str, git_section, required_tags,
                _PHASE16I_DIAGNOSIS["review_package_not_found"],
                [f"Review package unparseable: {review_package_path}"],
            )
        if rp_loaded.get("status") != "review_only":
            return _phase16i_no_go(
                drill_id, ts_str, git_section, required_tags,
                _PHASE16I_DIAGNOSIS["review_package_not_review_only"],
                [f"Review package status is '{rp_loaded.get('status')}', not 'review_only'",
                 "Re-run 16H to generate a valid review package"],
            )
        review_package_source = "loaded_from_prior_16h_artifact"
        review_package_path_actual = str(rp_path_obj.resolve())
        package_id = rp_loaded.get("package_id", "loaded-package")
        package_is_review_only = True
        review_items = rp_loaded.get("items", [])
        # Ensure safe defaults for loaded items
        for it in review_items:
            it.setdefault("executable", False)
            it.setdefault("requires_chris_approval", True)
            it.setdefault("performed", False)

    if not review_items and not review_package_path:
        # Synthesize internally (only when no --review-package given)
        candidate_pool = _REVIEW_CANDIDATE_POOL
        for i in range(min(effective_candidates, len(candidate_pool))):
            candidate = candidate_pool[i]
            rid = f"synthetic-review-item-{drill_id}-{i+1:03d}"
            review_items.append({
                "review_id": rid,
                "source": "synthetic_readonly_demo",
                "symbol": candidate["symbol"],
                "side": candidate["side"],
                "quantity": (i + 1) * 10,
                "rationale": candidate["rationale"],
                "risk_notes": f"Synthetic demo review item — not executable.",
                "executable": False,
                "requires_chris_approval": True,
                "performed": False,
                "review_status": "pending_review",
                "review_checklist": [
                    {"step": "verify_safety_locks", "description": "Confirm all safety locks engaged", "passed": True},
                    {"step": "verify_guard_clean", "description": "Confirm guard-state is clean", "passed": True},
                    {"step": "chris_approval", "description": "Chris explicitly approves this item", "passed": False},
                ],
            })
        package_id = f"synthetic-package-{ts_file}"

    # Package hash for integrity
    package_hashable = {
        "package_id": package_id,
        "items_count": len(review_items),
    }
    package_hash = _compute_evidence_hash(package_hashable)

    input_review_package = {
        "source": review_package_source,
        "package_id": package_id,
        "package_path": review_package_path_actual,
        "status": "review_only",
        "review_only": True,
        "items_count": len(review_items),
        "package_hash": package_hash,
    }

    # ------------------------------------------------------------------
    # 9. Apply decisions
    # ------------------------------------------------------------------
    decision_fn = _DECISION_LOGIC.get(decision_mode, _DECISION_LOGIC["mixed_demo"])
    decision_items: list[dict[str, Any]] = []
    accepted_count = 0
    rejected_count = 0
    deferred_count = 0

    for i, item in enumerate(review_items):
        verdict = decision_fn(i, item)
        reason = _DECISION_RATIONALE_TEMPLATES.get(verdict, "No decision.")
        decision_item: dict[str, Any] = {
            "proposal_id": f"decision-{drill_id}-{i+1:03d}",
            "review_id": item.get("review_id", f"item-{i}"),
            "symbol": item.get("symbol", "?"),
            "side": item.get("side", "?"),
            "quantity": item.get("quantity", 0),
            "original_executable": item.get("executable", False),
            "original_requires_approval": item.get("requires_chris_approval", True),
            "decision": verdict,
            "decision_reason": reason,
            "executable": False,
            "performed": False,
            "requires_chris_approval": True,
            "requires_future_order_window": True,
            "requires_future_h1": True,
            "future_required_path": "/order/preflight -> /order/approve -> /order/submit",
        }
        decision_items.append(decision_item)
        if verdict == "accept":
            accepted_count += 1
        elif verdict == "reject":
            rejected_count += 1
        else:
            deferred_count += 1

    decision_id = f"review-decision-{ts_file}"
    review_decision = {
        "decision_id": decision_id,
        "reviewer": "Chris",
        "decision_mode": decision_mode,
        "status": "audit_only",
        "decisions_count": len(decision_items),
        "accepted_count": accepted_count,
        "rejected_count": rejected_count,
        "deferred_count": deferred_count,
        "executable": False,
        "accepted_items_executable": False,
        "requires_future_order_window": True,
        "requires_future_h1": True,
        "future_required_path": "/order/preflight -> /order/approve -> /order/submit",
        "decision_items": decision_items,
    }

    # Decision artifact (standalone)
    decision_artifact = {
        "artifact_id": decision_id,
        "drill_id": drill_id,
        "status": "audit_only",
        "generated_by": "level1-review-decision-drill (Phase 16I)",
        "review_package": input_review_package,
        "review_decision": review_decision,
    }
    decision_artifact_hash = _compute_evidence_hash(decision_artifact)

    # ------------------------------------------------------------------
    # 10. Review workflow
    # ------------------------------------------------------------------
    review_workflow = {
        "decision_only": True,
        "demo_candidates_requested": effective_candidates,
        "items_examined": len(review_items),
        "decisions_applied": len(decision_items),
        "accepted_items_executable": False,
        "any_executable_item": False,
        "order_routing_disallowed": True,
        "broker_submission_performed": False,
        "preflight_performed": False,
        "approval_performed": False,
        "submit_performed": False,
    }

    workflow_summary = {
        "review_decision_ready": True,
        "decision_artifact_created": len(decision_items) > 0,
        "all_decisions_audit_only": True,
        "accepted_items_non_executable": accepted_count == 0 or review_decision["accepted_items_executable"] is False,
        "all_items_require_future_order_window": True,
        "all_items_require_future_h1": True,
        "no_order_path_called": True,
        "no_broker_submission": True,
        "no_h1_seen": True,
        "no_order_window_seen": True,
    }

    # ------------------------------------------------------------------
    # 11. Classification
    # ------------------------------------------------------------------
    all_tags_present = len(required_tags_missing) == 0
    worktree_clean = git_section.get("worktree_clean", False)
    run_time_ready = br_connected and br_mode == "paper" and br_read_only
    safety_locked = env_allow_orders in ("false", "?") and rules_enforced in ("false", "?") and system_locked is True

    if not all_tags_present:
        diagnosis = _PHASE16I_DIAGNOSIS["missing_required_tags"]
        severity = "NO_GO"
    elif not worktree_clean and worktree_clean is not None:
        diagnosis = _PHASE16I_DIAGNOSIS["dirty_worktree"]
        severity = "NO_GO"
    elif not positions_flat and positions_count > 0:
        diagnosis = _PHASE16I_DIAGNOSIS["positions_not_flat"]
        severity = "NO_GO"
    elif active_alerts_count > 0:
        diagnosis = _PHASE16I_DIAGNOSIS["monitor_alerts_active"]
        severity = "NO_GO"
    elif not run_time_ready:
        diagnosis = _PHASE16I_DIAGNOSIS["runtime_not_ready"]
        severity = "HOLD" if not br_connected else "NO_GO"
    elif not safety_locked:
        diagnosis = _PHASE16I_DIAGNOSIS["safety_not_locked"]
        severity = "NO_GO"
    elif autonomy_level != "1":
        diagnosis = _PHASE16I_DIAGNOSIS["autonomy_not_level1"]
        severity = "NO_GO"
    elif not gs_assessment["guard_state_clean"]:
        diagnosis = _PHASE16I_DIAGNOSIS["guard_state_not_clean"]
        severity = "NO_GO"
    elif not doc_acceptable:
        diagnosis = _PHASE16I_DIAGNOSIS["doctor_not_acceptable"]
        severity = "NO_GO"
    elif not kpi_acceptable_hold:
        diagnosis = _PHASE16I_DIAGNOSIS["kpi_not_acceptable"]
        severity = "NO_GO"
    elif not policy_result["hermes_policy_exists"] or not policy_result["execution_path_ok"]:
        diagnosis = _PHASE16I_DIAGNOSIS["policy_boundary_missing"]
        severity = "NO_GO"
    elif not clean_cycles_matches_kpi:
        diagnosis = _PHASE16I_DIAGNOSIS["clean_cycles_mismatch"]
        severity = "NO_GO"
    else:
        diagnosis = _PHASE16I_DIAGNOSIS["ready"]
        severity = "OK"

    drill_ok = diagnosis == _PHASE16I_DIAGNOSIS["ready"]
    operator_action_required = not drill_ok
    suggested_actions: list[str] = []
    if not drill_ok:
        suggested_actions.append(f"Review decision drill blocked: {diagnosis}")
        if not run_time_ready:
            suggested_actions.append("Ensure bridge is connected in paper read-only mode")
        if not safety_locked:
            suggested_actions.append("Verify all safety locks are engaged")
        if not gs_assessment["guard_state_clean"]:
            suggested_actions.append("Run guard-state-reconcile to fix guard state")

    # ------------------------------------------------------------------
    # 12. Evidence hash
    # ------------------------------------------------------------------
    hashable = {
        "diagnosis": diagnosis, "severity": severity,
        "decisions_count": len(decision_items),
        "accepted_count": accepted_count,
        "rejected_count": rejected_count,
        "deferred_count": deferred_count,
        "accepted_items_executable": False,
        "no_broker_mutation": True,
        "no_order_window_opened": True,
    }
    evidence_hash = _compute_evidence_hash(hashable)

    # ------------------------------------------------------------------
    # 13. Assemble result
    # ------------------------------------------------------------------
    result: dict[str, Any] = {
        "command": "ibkr-operator level1-review-decision-drill",
        "advisory": (
            "Read-only Level 1 review decision drill (Phase 16I). "
            "Applies accept/reject/defer decisions to a review package. "
            "Accepted items remain advisory/audit only — NOT executable. "
            "No orders. No mutations. No H1 token. No broker activity. "
            "No autonomy level change."
        ),
        "timestamp": ts_str,
        "drill_id": drill_id,
        "diagnosis": diagnosis,
        "severity": severity,
        "operator_action_required": operator_action_required,
        "suggested_operator_actions": suggested_actions,
        "git": git_section,
        "required_tags": required_tags,
        "runtime": runtime_section,
        "autonomy": autonomy_section,
        "safety": safety_section,
        "guard_state": guard_section,
        "input_review_package": input_review_package,
        "review_decision": review_decision,
        "decision_artifact": decision_artifact,
        "decision_artifact_hash": decision_artifact_hash,
        "review_workflow": review_workflow,
        "workflow_summary": workflow_summary,
        "kpi_summary": kpi_section,
        "doctor_summary": doctor_section,
        "policy_summary": policy_section,
        "promotion_allowed_now": False,
        "order_enablement_allowed_now": False,
        "order_enablement_performed": False,
        "promotion_performed": False,
        "no_broker_mutation": True,
        "no_order_window_opened": True,
        "no_order_window_seen": True,
        "no_h1_seen": True,
        "h1_token_not_used": True,
        "evidence_hash": evidence_hash,
        "explicit_non_actions": _PHASE16I_EXPLICIT_NON_ACTIONS,
    }

    # ------------------------------------------------------------------
    # 14. Export artifacts
    # ------------------------------------------------------------------
    export_path: str | None = None
    decision_artifact_path: str | None = None
    try:
        _PHASE16I_EXPORT_DIR.mkdir(parents=True, exist_ok=True)
        ep = _PHASE16I_EXPORT_DIR / f"{drill_id}.json"
        with open(ep, "w", encoding="utf-8") as f:
            _json.dump(result, f, indent=2, default=str)
        export_path = str(ep)
        da_path = _PHASE16I_EXPORT_DIR / f"{decision_id}.json"
        with open(da_path, "w", encoding="utf-8") as f:
            _json.dump(decision_artifact, f, indent=2, default=str)
        decision_artifact_path = str(da_path)
    except Exception:
        pass

    result["export_path"] = export_path
    result["decision_artifact_path"] = decision_artifact_path
    return result


def _phase16i_no_go(
    drill_id: str, ts_str: str, git_section: dict, required_tags: dict,
    diagnosis: str, actions: list,
) -> dict:
    """Build a NO_GO result for early-exit prerequisite failures."""
    empty_decision = {"decisions_count": 0, "accepted_count": 0, "rejected_count": 0, "deferred_count": 0}
    empty_da = {"status": "blocked", "artifact_id": drill_id}
    return {
        "command": "ibkr-operator level1-review-decision-drill",
        "timestamp": ts_str,
        "drill_id": drill_id,
        "diagnosis": diagnosis,
        "severity": "NO_GO",
        "operator_action_required": True,
        "suggested_operator_actions": actions,
        "git": git_section,
        "required_tags": required_tags,
        "runtime": {},
        "autonomy": {},
        "safety": {},
        "guard_state": {},
        "input_review_package": {},
        "review_decision": {**empty_decision, "decision_items": []},
        "decision_artifact": empty_da,
        "decision_artifact_hash": _compute_evidence_hash(empty_da),
        "review_workflow": {},
        "workflow_summary": {},
        "kpi_summary": {},
        "doctor_summary": {},
        "policy_summary": {},
        "promotion_allowed_now": False,
        "order_enablement_allowed_now": False,
        "order_enablement_performed": False,
        "promotion_performed": False,
        "no_broker_mutation": True,
        "no_order_window_opened": True,
        "no_order_window_seen": True,
        "no_h1_seen": True,
        "h1_token_not_used": True,
        "evidence_hash": _compute_evidence_hash({"diagnosis": diagnosis}),
        "explicit_non_actions": _PHASE16I_EXPLICIT_NON_ACTIONS,
    }


def _print_level1_review_decision_drill(result: dict) -> None:
    """Print Phase 16I review decision drill in human-readable format."""
    drill_ok = result.get("diagnosis") == _PHASE16I_DIAGNOSIS["ready"]
    diag_color = GREEN if drill_ok else RED
    sev = result.get("severity", "?")
    sev_color = GREEN if sev == "OK" else (YELLOW if sev == "HOLD" else RED)

    print(f"{BOLD}══════════════════════════════════════════════════{RESET}")
    print(f"{BOLD}  Level 1 Review Decision Drill (16I){RESET}")
    print(f"{BOLD}══════════════════════════════════════════════════{RESET}\\n")
    print(f"  Drill ID:           {result.get('drill_id', '?')}")
    print(f"  Timestamp:          {result.get('timestamp', '?')}")
    print(f"  Diagnosis:          {diag_color}{result.get('diagnosis', '?')}{RESET}")
    print(f"  Severity:           {sev_color}{sev}{RESET}")
    print()

    irp = result.get("input_review_package", {})
    if irp:
        print(f"  {BOLD}Input Review Package{RESET}")
        print(f"    Source:           {irp.get('source', '?')}")
        print(f"    Package ID:       {irp.get('package_id', '?')}")
        print(f"    Items count:      {irp.get('items_count', 0)}")
        pph = irp.get("package_hash", "")
        if pph:
            print(f"    Package hash:     {pph[:16]}...")
        print()

    rd = result.get("review_decision", {})
    if rd:
        print(f"  {BOLD}Review Decision{RESET}")
        print(f"    Decision ID:      {rd.get('decision_id', '?')}")
        print(f"    Reviewer:         {rd.get('reviewer', '?')}")
        print(f"    Mode:             {rd.get('decision_mode', '?')}")
        print(f"    Status:           {rd.get('status', '?')}")
        print(f"    Total decisions:  {rd.get('decisions_count', 0)}")
        print(f"    Accepted:         {GREEN}{rd.get('accepted_count', 0)}{RESET}")
        print(f"    Rejected:         {RED}{rd.get('rejected_count', 0)}{RESET}")
        print(f"    Deferred:         {YELLOW}{rd.get('deferred_count', 0)}{RESET}")
        print(f"    Executable:        {RED}{rd.get('executable', '?')}{RESET}")
        print(f"    Accepted exec:     {RED}{rd.get('accepted_items_executable', '?')}{RESET}")
        print()

        decisions = rd.get("decision_items", [])
        if decisions:
            print(f"  {BOLD}Decision Details{RESET}")
            for d in decisions:
                d_verdict = d.get("decision", "?")
                v_color = GREEN if d_verdict == "accept" else (RED if d_verdict == "reject" else YELLOW)
                print(f"    {d.get('proposal_id', '?')}: {d.get('symbol', '?')} "
                      f"{v_color}{d_verdict.upper()}{RESET} "
                      f"qty={d.get('quantity', 0)} exec={RED}{d.get('executable')}{RESET}")
            print()

    rw = result.get("review_workflow", {})
    if rw:
        print(f"  {BOLD}Review Workflow{RESET}")
        print(f"    Decision-only:         {rw.get('decision_only')}")
        print(f"    Items examined:        {rw.get('items_examined', 0)}")
        print(f"    Decisions applied:     {rw.get('decisions_applied', 0)}")
        print(f"    Accepted exec:         {RED}{rw.get('accepted_items_executable')}{RESET}")
        print(f"    Broker submission:     {RED}{rw.get('broker_submission_performed')}{RESET}")
        print()

    ws = result.get("workflow_summary", {})
    if ws:
        print(f"  {BOLD}Workflow Summary{RESET}")
        for key, val in ws.items():
            color = GREEN if val else RED
            print(f"    {key:<42} {color}{val}{RESET}")
        print()

    auto = result.get("autonomy", {})
    if auto:
        print(f"  {BOLD}Autonomy{RESET}")
        print(f"    Level:          {auto.get('current_level', '?')}")
        cc = auto.get('clean_cycles')
        print(f"    Clean cycles:   {cc if cc is not None else 'null'}")
        print(f"    Matches KPI:    {auto.get('clean_cycles_matches_kpi')}")
        print()

    safety = result.get("safety", {})
    if safety:
        print(f"  {BOLD}Safety{RESET}")
        print(f"    ALLOW_ORDERS:   {safety.get('env_IBKR_ALLOW_ORDERS', '?')}")
        print(f"    rules.enforced: {safety.get('rules_enforced', '?')}")
        print(f"    system_locked:  {_bool_str(safety.get('system_locked'))}")
        print()

    runtime = result.get("runtime", {})
    if runtime:
        print(f"  {BOLD}Runtime{RESET}")
        print(f"    Bridge:         connected={_bool_str(runtime.get('bridge_connected'))} mode={runtime.get('mode', '?')}")
        print(f"    Endpoints:      {runtime.get('endpoints_display', '?')}")
        print(f"    Positions:      {runtime.get('positions_count', 0)}  flat={_bool_str(runtime.get('positions_flat'))}")
        print(f"    Alerts:         {runtime.get('active_alerts_count', 0)}")
        print()

    guard = result.get("guard_state", {})
    if guard:
        print(f"  {BOLD}Guard State{RESET}")
        print(f"    Trade count:    {guard.get('daily_trade_count', '?')}")
        print(f"    Trade date:     {guard.get('trade_date', '?')}")
        print(f"    Stale:          {_bool_str(guard.get('trade_date_stale'))}")
        print(f"    Clean:          {_bool_str(guard.get('guard_state_clean'))}")
        print()

    sa = result.get("suggested_operator_actions", [])
    if sa:
        print(f"  {BOLD}Suggested Actions{RESET}")
        for a in sa:
            print(f"    {YELLOW}→{RESET} {a}")
        print()

    print(f"  {BOLD}Advisory{RESET}")
    print(f"    {result.get('advisory', '')}")

    eh = result.get("evidence_hash", "")
    if eh:
        print(f"\n  Evidence hash: {eh[:16]}...")

    ep = result.get("export_path")
    if ep:
        print(f"  Export: {ep}")
    da = result.get("decision_artifact_path")
    if da:
        print(f"  Decision artifact: {da}")
    dah = result.get("decision_artifact_hash", "")
    if dah:
        print(f"  Decision artifact hash: {dah[:16]}...")
    print()


